1	import { parseFrontmatter } from '../frontmatter.js';
2	import type {
3	  Document, Section, Node, Task, TextNode, HeadingNode, TableNode, BlankNode,
4	  TaskStatus, Wikilink, DocLink,
5	} from './types.js';
6	import { STATUS_CHARS } from './types.js';
7	
8	// ── Wikilink parsing ──────────────────────────────────────────────────
9	
10	function parseWikilink(raw: string): Wikilink {
11	  const match = /^\[\[([^\]|]+)(?:\|([^\]]+))?\]\]$/.exec(raw.trim());
12	  if (!match) return { path: raw };
13	  return { path: match[1], alias: match[2] };
14	}
15	
16	// ── Table parsing ─────────────────────────────────────────────────────
17	
18	function parseTableCells(line: string): string[] {
19	  // Split on | but respect backtick-wrapped expressions
20	  const cells: string[] = [];
21	  let current = '';
22	  let inBacktick = false;
23	  for (let i = 0; i < line.length; i++) {
24	    const ch = line[i];
25	    if (ch === '`') {
26	      inBacktick = !inBacktick;
27	      current += ch;
28	    } else if (ch === '|' && !inBacktick) {
29	      cells.push(current.trim());
30	      current = '';
31	    } else {
32	      current += ch;
33	    }
34	  }
35	  cells.push(current.trim());
36	  // Remove leading/trailing empty cells from pipe-delimited lines
37	  if (cells[0] === '') cells.shift();
38	  if (cells[cells.length - 1] === '') cells.pop();
39	  return cells;
40	}
41	
42	function isTableSeparator(line: string): boolean {
43	  return /^\|[\s\-:|]+\|/.test(line);
44	}
45	
46	// ── Task line parsing ─────────────────────────────────────────────────
47	
48	function parseTaskLine(line: string, lineNum: number): Task | null {
49	  // Measure indent
50	  const indentMatch = /^(\s*)/.exec(line);
51	  const indent = indentMatch ? indentMatch[1].length : 0;
52	  const trimmed = line.trimStart();
53	
54	  // Check for label: - **[N] ...** (no checkbox)
55	  const isLabel = /^-\s+\*\*\[/.test(trimmed);
56	
57	  // Check for checkbox task
58	  const checkboxMatch = /^-\s+\[(.)\]\s+/.exec(trimmed);
59	
60	  if (!isLabel && !checkboxMatch) return null;
61	
62	  let status: TaskStatus = 'todo';
63	  let rest = trimmed;
64	
65	  if (isLabel) {
66	    // - **[N] content** or - **[N] ~~content~~ → [[...]]**
67	    rest = trimmed.replace(/^-\s+\*\*/, '').replace(/\*\*$/, '');
68	  } else if (checkboxMatch) {
69	    const statusChar = checkboxMatch[1];
70	    status = STATUS_CHARS[statusChar] ?? 'todo';
71	    rest = trimmed.slice(checkboxMatch[0].length);
72	  }
73	
74	  // Extract bracket ID: [5] or [5.3]
75	  let id = '';
76	  const bracketIdMatch = /^\[(\d+(?:\.\d+)*)\]\s*/.exec(rest);
77	  if (bracketIdMatch) {
78	    id = bracketIdMatch[1];
79	    rest = rest.slice(bracketIdMatch[0].length);
80	  }
81	
82	  // For labels: check if rest has a [log] prefix (like [-] [10] [log] ...)
83	  // Actually [log] appears after bracket ID in checkbox tasks
84	  // e.g. "- [-] [10] [log] Cancelled task"
85	  // Already consumed by bracket ID extraction if it's [N], but [log] is literal text
86	  // Keep it in content — do not extract
87	
88	  // Extract doc links: (📄 [[path|N]] [[path|N]])
89	  const links: DocLink[] = [];
90	  const docLinkBlockRegex = /\(📄\s*((?:\[\[[^\]]+\]\]\s*)+)\)/;
91	  const docLinkMatch = docLinkBlockRegex.exec(rest);
92	  if (docLinkMatch) {
93	    const inner = docLinkMatch[1];
94	    const wlRegex = /\[\[([^\]|]+)(?:\|([^\]]+))?\]\]/g;
95	    let wlMatch;
96	    while ((wlMatch = wlRegex.exec(inner)) !== null) {
97	      const path = wlMatch[1];
98	      const num = wlMatch[2] ? parseInt(wlMatch[2], 10) : 0;
99	      links.push({ path, number: num });
100	    }
101	    rest = rest.replace(docLinkBlockRegex, '').trimEnd();
102	  }
103	
104	  // Extract carry-forward history: ← [[path|alias]]
105	  // For deferred tasks, the content may be wrapped in ~~ including history
106	  // e.g. ~~content ← [[...]] ← [[...]~~ → [[...]]
107	  // We need to handle the strikethrough wrapper first
108	  const history: Wikilink[] = [];
109	  let forward: Wikilink | undefined;
110	  let isStrikethrough = false;
111	
112	  // Check if the entire rest is wrapped in ~~...~~ → [[...]]
113	  // Pattern: ~~(content)~~ → [[path|alias]]
114	  const deferredMatch = /^~~(.+)~~\s*→\s*(\[\[[^\]]+(?:\|[^\]]+)?\]\])$/.exec(rest);
115	  if (deferredMatch) {
116	    isStrikethrough = true;
117	    const innerContent = deferredMatch[1];
118	    const forwardRaw = deferredMatch[2];
119	    forward = parseWikilink(forwardRaw);
120	
121	    // Extract history from inner content
122	    const histRegex = /←\s*\[\[([^\]|]+)(?:\|([^\]]+))?\]\]/g;
123	    let histMatch;
124	    while ((histMatch = histRegex.exec(innerContent)) !== null) {
125	      history.push({ path: histMatch[1], alias: histMatch[2] });
126	    }
127	    // Remove history from content
128	    rest = innerContent.replace(/\s*←\s*\[\[[^\]]+(?:\|[^\]]+)?\]\]/g, '').trimEnd();
129	  } else {
130	    // Not deferred strikethrough — extract history and forward from rest normally
131	    const histRegex = /←\s*\[\[([^\]|]+)(?:\|([^\]]+))?\]\]/g;
132	    let histMatch;
133	    while ((histMatch = histRegex.exec(rest)) !== null) {
134	      history.push({ path: histMatch[1], alias: histMatch[2] });
135	    }
136	    if (history.length > 0) {
137	      rest = rest.replace(/\s*←\s*\[\[[^\]]+(?:\|[^\]]+)?\]\]/g, '').trimEnd();
138	    }
139	
140	    // Extract forward link: → [[path|alias]]
141	    const forwardMatch = /→\s*\[\[([^\]|]+)(?:\|([^\]]+))?\]\]/.exec(rest);
142	    if (forwardMatch) {
143	      forward = { path: forwardMatch[1], alias: forwardMatch[2] };
144	      rest = rest.replace(/\s*→\s*\[\[[^\]]+(?:\|[^\]]+)?\]\]/, '').trimEnd();
145	    }
146	
147	    // Check if remaining content is wrapped in ~~ (non-deferred strikethrough)
148	    const stMatch = /^~~(.+)~~$/.exec(rest);
149	    if (stMatch) {
150	      isStrikethrough = true;
151	      rest = stMatch[1];
152	    }
153	  }
154	
155	  // Extract completion: ✅ YYYY-MM-DD
156	  let completion: string | undefined;
157	  const completionMatch = /✅\s*(\d{4}-\d{2}-\d{2})/.exec(rest);
158	  if (completionMatch) {
159	    completion = completionMatch[1];
160	    rest = rest.replace(/\s*✅\s*\d{4}-\d{2}-\d{2}/, '').trimEnd();
161	  }
162	
163	  // Extract cancellation: ❌ YYYY-MM-DD - reason
164	  let cancellation: string | undefined;
165	  let cancelReason: string | undefined;
166	  const cancellationMatch = /❌\s*(\d{4}-\d{2}-\d{2})(?:\s*-\s*(.+))?/.exec(rest);
167	  if (cancellationMatch) {
168	    cancellation = cancellationMatch[1];
169	    cancelReason = cancellationMatch[2];
170	    rest = rest.replace(/\s*❌\s*\d{4}-\d{2}-\d{2}(?:\s*-\s*.+)?/, '').trimEnd();
171	  }
172	
173	  const content = rest;
174	
175	  return {
176	    type: 'task',
177	    line: lineNum,
178	    raw: line,
179	    dirty: false,
180	    id,
181	    status,
182	    content,
183	    subtasks: [],
184	    indent,
185	    links,
186	    history,
187	    forward,
188	    completion,
189	    cancellation,
190	    cancelReason,
191	    isLabel,
192	    isStrikethrough,
193	  };
194	}
195	
196	// ── Main parse function ───────────────────────────────────────────────
197	
198	export function parse(markdown: string): Document {
199	  // Normalize line endings
200	  const normalized = markdown.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
201	
202	  const lines = normalized.split('\n');
203	
204	  // Detect frontmatter
205	  let frontmatterRaw = '';
206	  let frontmatter: Record<string, any> = {};
207	  let bodyStart = 0;
208	
209	  if (lines[0]?.trim() === '---') {
210	    const secondDelim = lines.findIndex((l, i) => i > 0 && l.trim() === '---');
211	    if (secondDelim >= 0) {
212	      frontmatterRaw = lines.slice(0, secondDelim + 1).join('\n');
213	      frontmatter = parseFrontmatter(normalized);
214	      bodyStart = secondDelim + 1;
215	    }
216	  }
217	
218	  const sections: Section[] = [];
219	  const preamble: Node[] = [];
220	  let currentSection: Section | null = null;
221	
222	  // Table accumulation state
223	  let tableLines: string[] = [];
224	  let tableStartLine = 0;
225	
226	  function flushTable(targetNodes: Node[]) {
227	    if (tableLines.length === 0) return;
228	    const rawTable = tableLines.join('\n');
229	    const headers = parseTableCells(tableLines[0]);
230	    const rows: string[][] = [];
231	    for (let i = 2; i < tableLines.length; i++) {
232	      rows.push(parseTableCells(tableLines[i]));
233	    }
234	    targetNodes.push({
235	      type: 'table',
236	      line: tableStartLine,
237	      raw: rawTable,
238	      dirty: false,
239	      headers,
240	      rows,
241	      rawLines: [...tableLines],
242	    } as TableNode);
243	    tableLines = [];
244	    tableStartLine = 0;
245	  }
246	
247	  function currentNodes(): Node[] {
248	    return currentSection ? currentSection.body : preamble;
249	  }
250	
251	  // Track last top-level task/label per section for sub-task attachment
252	  let lastTopLevelTask: Task | null = null;
253	
254	  function onSectionChange() {
255	    lastTopLevelTask = null;
256	  }
257	
258	  for (let i = bodyStart; i < lines.length; i++) {
259	    const line = lines[i];
260	    const lineNum = i + 1; // 1-based
261	
262	    // Check if this is a table line
263	    const isTableLine = line.startsWith('|');
264	
265	    if (!isTableLine && tableLines.length > 0) {
266	      // Flush accumulated table to current nodes
267	      flushTable(currentNodes());
268	    }
269	
270	    if (isTableLine) {
271	      if (tableLines.length === 0) tableStartLine = lineNum;
272	      tableLines.push(line);
273	      continue;
274	    }
275	
276	    // Heading detection
277	    const headingMatch = /^(#{1,6})\s+(.+)$/.exec(line);
278	    if (headingMatch) {
279	      const level = headingMatch[1].length;
280	      const content = headingMatch[2];
281	
282	      if (level === 2) {
283	        // Start new section
284	        onSectionChange();
285	        currentSection = {
286	          heading: content,
287	          level: 2,
288	          body: [],
289	          line: lineNum,
290	          raw: line,
291	        };
292	        sections.push(currentSection);
293	        continue;
294	      } else {
295	        // Level 3+ heading inside section body
296	        const node: HeadingNode = {
297	          type: 'heading',
298	          line: lineNum,
299	          raw: line,
300	          dirty: false,
301	          level,
302	          content,
303	        };
304	        currentNodes().push(node);
305	        continue;
306	      }
307	    }
308	
309	    // Blank line
310	    if (line.trim() === '') {
311	      const node: BlankNode = {
312	        type: 'blank',
313	        line: lineNum,
314	        raw: line,
315	        dirty: false,
316	      };
317	      currentNodes().push(node);
318	      continue;
319	    }
320	
321	    // Task line (checkbox or label)
322	    const task = parseTaskLine(line, lineNum);
323	    if (task) {
324	      if (task.indent > 0) {
325	        // Sub-task: attach to last top-level task/label
326	        if (lastTopLevelTask) {
327	          lastTopLevelTask.subtasks.push(task);
328	        } else {
329	          // No parent — treat as standalone (defensive)
330	          console.warn(`[obsidian-md] Sub-task at line ${lineNum} has no parent — treating as top-level`);
331	          currentNodes().push(task);
332	        }
333	      } else {
334	        // Top-level task
335	        currentNodes().push(task);
336	        lastTopLevelTask = task;
337	      }
338	      continue;
339	    }
340	
341	    // Text node
342	    const textNode: TextNode = {
343	      type: 'text',
344	      line: lineNum,
345	      raw: line,
346	      dirty: false,
347	      content: line,
348	    };
349	    currentNodes().push(textNode);
350	  }
351	
352	  // Flush any trailing table
353	  if (tableLines.length > 0) {
354	    flushTable(currentNodes());
355	  }
356	
357	  return {
358	    frontmatter,
359	    frontmatterRaw,
360	    preamble,
361	    sections,
362	    raw: normalized,
363	  };
364	}
