import { parseFrontmatter } from '../frontmatter.js';
import type {
  Document, Section, Node, Task, TextNode, HeadingNode, TableNode, BlankNode,
  TaskStatus, Wikilink, DocLink,
} from './types.js';
import { STATUS_CHARS } from './types.js';

// ── Wikilink parsing ──────────────────────────────────────────────────

function parseWikilink(raw: string): Wikilink {
  const match = /^\[\[([^\]|]+)(?:\|([^\]]+))?\]\]$/.exec(raw.trim());
  if (!match) return { path: raw };
  return { path: match[1], alias: match[2] };
}

// ── Table parsing ─────────────────────────────────────────────────────

function parseTableCells(line: string): string[] {
  // Split on | but respect backtick-wrapped expressions
  const cells: string[] = [];
  let current = '';
  let inBacktick = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === '`') {
      inBacktick = !inBacktick;
      current += ch;
    } else if (ch === '|' && !inBacktick) {
      cells.push(current.trim());
      current = '';
    } else {
      current += ch;
    }
  }
  cells.push(current.trim());
  // Remove leading/trailing empty cells from pipe-delimited lines
  if (cells[0] === '') cells.shift();
  if (cells[cells.length - 1] === '') cells.pop();
  return cells;
}

function isTableSeparator(line: string): boolean {
  return /^\|[\s\-:|]+\|/.test(line);
}

// ── Task line parsing ─────────────────────────────────────────────────

function parseTaskLine(line: string, lineNum: number): Task | null {
  // Measure indent
  const indentMatch = /^(\s*)/.exec(line);
  const indent = indentMatch ? indentMatch[1].length : 0;
  const trimmed = line.trimStart();

  // Check for label: - **[N] ...** (no checkbox)
  const isLabel = /^-\s+\*\*\[/.test(trimmed);

  // Check for checkbox task
  const checkboxMatch = /^-\s+\[(.)\]\s+/.exec(trimmed);

  if (!isLabel && !checkboxMatch) return null;

  let status: TaskStatus = 'todo';
  let rest = trimmed;

  if (isLabel) {
    // - **[N] content** or - **[N] ~~content~~ → [[...]]**
    rest = trimmed.replace(/^-\s+\*\*/, '').replace(/\*\*$/, '');
  } else if (checkboxMatch) {
    const statusChar = checkboxMatch[1];
    status = STATUS_CHARS[statusChar] ?? 'todo';
    rest = trimmed.slice(checkboxMatch[0].length);
  }

  // Extract bracket ID: [5] or [5.3]
  let id = '';
  const bracketIdMatch = /^\[(\d+(?:\.\d+)*)\]\s*/.exec(rest);
  if (bracketIdMatch) {
    id = bracketIdMatch[1];
    rest = rest.slice(bracketIdMatch[0].length);
  }

  // For labels: check if rest has a [log] prefix (like [-] [10] [log] ...)
  // Actually [log] appears after bracket ID in checkbox tasks
  // e.g. "- [-] [10] [log] Cancelled task"
  // Already consumed by bracket ID extraction if it's [N], but [log] is literal text
  // Keep it in content — do not extract

  // Extract doc links: (📄 [[path|N]] [[path|N]])
  const links: DocLink[] = [];
  const docLinkBlockRegex = /\(📄\s*((?:\[\[[^\]]+\]\]\s*)+)\)/;
  const docLinkMatch = docLinkBlockRegex.exec(rest);
  if (docLinkMatch) {
    const inner = docLinkMatch[1];
    const wlRegex = /\[\[([^\]|]+)(?:\|([^\]]+))?\]\]/g;
    let wlMatch;
    while ((wlMatch = wlRegex.exec(inner)) !== null) {
      const path = wlMatch[1];
      const num = wlMatch[2] ? parseInt(wlMatch[2], 10) : 0;
      links.push({ path, number: num });
    }
    rest = rest.replace(docLinkBlockRegex, '').trimEnd();
  }

  // Extract carry-forward history: ← [[path|alias]]
  // For deferred tasks, the content may be wrapped in ~~ including history
  // e.g. ~~content ← [[...]] ← [[...]~~ → [[...]]
  // We need to handle the strikethrough wrapper first
  const history: Wikilink[] = [];
  let forward: Wikilink | undefined;
  let isStrikethrough = false;

  // Check if the entire rest is wrapped in ~~...~~ → [[...]]
  // Pattern: ~~(content)~~ → [[path|alias]]
  const deferredMatch = /^~~(.+)~~\s*→\s*(\[\[[^\]]+(?:\|[^\]]+)?\]\])$/.exec(rest);
  if (deferredMatch) {
    isStrikethrough = true;
    const innerContent = deferredMatch[1];
    const forwardRaw = deferredMatch[2];
    forward = parseWikilink(forwardRaw);

    // Extract history from inner content
    const histRegex = /←\s*\[\[([^\]|]+)(?:\|([^\]]+))?\]\]/g;
    let histMatch;
    while ((histMatch = histRegex.exec(innerContent)) !== null) {
      history.push({ path: histMatch[1], alias: histMatch[2] });
    }
    // Remove history from content
    rest = innerContent.replace(/\s*←\s*\[\[[^\]]+(?:\|[^\]]+)?\]\]/g, '').trimEnd();
  } else {
    // Not deferred strikethrough — extract history and forward from rest normally
    const histRegex = /←\s*\[\[([^\]|]+)(?:\|([^\]]+))?\]\]/g;
    let histMatch;
    while ((histMatch = histRegex.exec(rest)) !== null) {
      history.push({ path: histMatch[1], alias: histMatch[2] });
    }
    if (history.length > 0) {
      rest = rest.replace(/\s*←\s*\[\[[^\]]+(?:\|[^\]]+)?\]\]/g, '').trimEnd();
    }

    // Extract forward link: → [[path|alias]]
    const forwardMatch = /→\s*\[\[([^\]|]+)(?:\|([^\]]+))?\]\]/.exec(rest);
    if (forwardMatch) {
      forward = { path: forwardMatch[1], alias: forwardMatch[2] };
      rest = rest.replace(/\s*→\s*\[\[[^\]]+(?:\|[^\]]+)?\]\]/, '').trimEnd();
    }

    // Check if remaining content is wrapped in ~~ (non-deferred strikethrough)
    const stMatch = /^~~(.+)~~$/.exec(rest);
    if (stMatch) {
      isStrikethrough = true;
      rest = stMatch[1];
    }
  }

  // Extract completion: ✅ YYYY-MM-DD
  let completion: string | undefined;
  const completionMatch = /✅\s*(\d{4}-\d{2}-\d{2})/.exec(rest);
  if (completionMatch) {
    completion = completionMatch[1];
    rest = rest.replace(/\s*✅\s*\d{4}-\d{2}-\d{2}/, '').trimEnd();
  }

  // Extract cancellation: ❌ YYYY-MM-DD - reason
  let cancellation: string | undefined;
  let cancelReason: string | undefined;
  const cancellationMatch = /❌\s*(\d{4}-\d{2}-\d{2})(?:\s*-\s*(.+))?/.exec(rest);
  if (cancellationMatch) {
    cancellation = cancellationMatch[1];
    cancelReason = cancellationMatch[2];
    rest = rest.replace(/\s*❌\s*\d{4}-\d{2}-\d{2}(?:\s*-\s*.+)?/, '').trimEnd();
  }

  const content = rest;

  return {
    type: 'task',
    line: lineNum,
    raw: line,
    dirty: false,
    id,
    status,
    content,
    subtasks: [],
    indent,
    links,
    history,
    forward,
    completion,
    cancellation,
    cancelReason,
    isLabel,
    isStrikethrough,
  };
}

// ── Main parse function ───────────────────────────────────────────────

export function parse(markdown: string): Document {
  // Normalize line endings
  const normalized = markdown.replace(/\r\n/g, '\n').replace(/\r/g, '\n');

  const lines = normalized.split('\n');

  // Detect frontmatter
  let frontmatterRaw = '';
  let frontmatter: Record<string, any> = {};
  let bodyStart = 0;

  if (lines[0]?.trim() === '---') {
    const secondDelim = lines.findIndex((l, i) => i > 0 && l.trim() === '---');
    if (secondDelim >= 0) {
      frontmatterRaw = lines.slice(0, secondDelim + 1).join('\n');
      frontmatter = parseFrontmatter(normalized);
      bodyStart = secondDelim + 1;
    }
  }

  const sections: Section[] = [];
  const preamble: Node[] = [];
  let currentSection: Section | null = null;

  // Table accumulation state
  let tableLines: string[] = [];
  let tableStartLine = 0;

  function flushTable(targetNodes: Node[]) {
    if (tableLines.length === 0) return;
    const rawTable = tableLines.join('\n');
    const headers = parseTableCells(tableLines[0]);
    const rows: string[][] = [];
    for (let i = 2; i < tableLines.length; i++) {
      rows.push(parseTableCells(tableLines[i]));
    }
    targetNodes.push({
      type: 'table',
      line: tableStartLine,
      raw: rawTable,
      dirty: false,
      headers,
      rows,
      rawLines: [...tableLines],
    } as TableNode);
    tableLines = [];
    tableStartLine = 0;
  }

  function currentNodes(): Node[] {
    return currentSection ? currentSection.body : preamble;
  }

  // Track last top-level task/label per section for sub-task attachment
  let lastTopLevelTask: Task | null = null;

  function onSectionChange() {
    lastTopLevelTask = null;
  }

  for (let i = bodyStart; i < lines.length; i++) {
    const line = lines[i];
    const lineNum = i + 1; // 1-based

    // Check if this is a table line
    const isTableLine = line.startsWith('|');

    if (!isTableLine && tableLines.length > 0) {
      // Flush accumulated table to current nodes
      flushTable(currentNodes());
    }

    if (isTableLine) {
      if (tableLines.length === 0) tableStartLine = lineNum;
      tableLines.push(line);
      continue;
    }

    // Heading detection
    const headingMatch = /^(#{1,6})\s+(.+)$/.exec(line);
    if (headingMatch) {
      const level = headingMatch[1].length;
      const content = headingMatch[2];

      if (level === 2) {
        // Start new section
        onSectionChange();
        currentSection = {
          heading: content,
          level: 2,
          body: [],
          line: lineNum,
          raw: line,
        };
        sections.push(currentSection);
        continue;
      } else {
        // Level 3+ heading inside section body
        const node: HeadingNode = {
          type: 'heading',
          line: lineNum,
          raw: line,
          dirty: false,
          level,
          content,
        };
        currentNodes().push(node);
        continue;
      }
    }

    // Blank line
    if (line.trim() === '') {
      const node: BlankNode = {
        type: 'blank',
        line: lineNum,
        raw: line,
        dirty: false,
      };
      currentNodes().push(node);
      continue;
    }

    // Task line (checkbox or label)
    const task = parseTaskLine(line, lineNum);
    if (task) {
      if (task.indent > 0) {
        // Sub-task: attach to last top-level task/label
        if (lastTopLevelTask) {
          lastTopLevelTask.subtasks.push(task);
        } else {
          // No parent — treat as standalone (defensive)
          console.warn(`[obsidian-md] Sub-task at line ${lineNum} has no parent — treating as top-level`);
          currentNodes().push(task);
        }
      } else {
        // Top-level task
        currentNodes().push(task);
        lastTopLevelTask = task;
      }
      continue;
    }

    // Text node
    const textNode: TextNode = {
      type: 'text',
      line: lineNum,
      raw: line,
      dirty: false,
      content: line,
    };
    currentNodes().push(textNode);
  }

  // Flush any trailing table
  if (tableLines.length > 0) {
    flushTable(currentNodes());
  }

  return {
    frontmatter,
    frontmatterRaw,
    preamble,
    sections,
    raw: normalized,
  };
}

