import { serializeFrontmatter } from '../frontmatter.js';
import type { Document, Node, Task, TextNode, HeadingNode, TableNode, BlankNode, Section } from './types.js';
import { STATUS_TO_CHAR } from './types.js';

// ── Task serialization ────────────────────────────────────────────────

function serializeTask(task: Task): string {
  const indent = ' '.repeat(task.indent);

  if (task.isLabel) {
    // - **[N] content** or - **[N] ~~content~~ → [[...]]**
    let line = `${indent}- **`;
    if (task.id) line += `[${task.id}] `;
    let content = task.content;
    if (task.isStrikethrough) content = `~~${content}~~`;
    line += content;
    if (task.forward) {
      line += ` → [[${task.forward.path}${task.forward.alias ? '|' + task.forward.alias : ''}]]`;
    }
    line += '**';
    return line;
  }

  const statusChar = STATUS_TO_CHAR[task.status];
  let line = `${indent}- [${statusChar}] `;
  if (task.id) line += `[${task.id}] `;

  let content = task.content;

  if (task.isStrikethrough) {
    // Deferred pattern: ~~content ← history~~ → forward
    let inner = content;
    for (const h of task.history) {
      inner += ` ← [[${h.path}${h.alias ? '|' + h.alias : ''}]]`;
    }
    line += `~~${inner}~~`;
    if (task.forward) {
      line += ` → [[${task.forward.path}${task.forward.alias ? '|' + task.forward.alias : ''}]]`;
    }
  } else {
    line += content;

    // Doc links
    if (task.links.length > 0) {
      const refs = task.links.map(l => `[[${l.path}|${l.number}]]`).join(' ');
      line += ` (📄 ${refs})`;
    }

    // History
    for (const h of task.history) {
      line += ` ← [[${h.path}${h.alias ? '|' + h.alias : ''}]]`;
    }

    // Forward
    if (task.forward) {
      line += ` → [[${task.forward.path}${task.forward.alias ? '|' + task.forward.alias : ''}]]`;
    }

    // Completion
    if (task.completion) line += ` ✅ ${task.completion}`;

    // Cancellation
    if (task.cancellation) {
      line += ` ❌ ${task.cancellation}`;
      if (task.cancelReason) line += ` - ${task.cancelReason}`;
    }
  }

  return line;
}

// ── Node serialization ────────────────────────────────────────────────

function serializeNode(node: Node): string {
  if (!node.dirty) return node.raw;

  switch (node.type) {
    case 'task': {
      const task = node as Task;
      const lines: string[] = [serializeTask(task)];
      for (const sub of task.subtasks) {
        lines.push(serializeNode(sub));
      }
      return lines.join('\n');
    }
    case 'text':
      return (node as TextNode).content;
    case 'heading': {
      const h = node as HeadingNode;
      return `${'#'.repeat(h.level)} ${h.content}`;
    }
    case 'table': {
      const t = node as TableNode;
      return t.rawLines.join('\n');
    }
    case 'blank':
      return '';
    default:
      return node.raw;
  }
}

// ── Document dirty check ──────────────────────────────────────────────

function isDocDirty(doc: Document): boolean {
  for (const node of doc.preamble) {
    if (node.dirty) return true;
    if (node.type === 'task') {
      for (const sub of (node as Task).subtasks) {
        if (sub.dirty) return true;
      }
    }
  }
  for (const section of doc.sections) {
    for (const node of section.body) {
      if (node.dirty) return true;
      if (node.type === 'task') {
        for (const sub of (node as Task).subtasks) {
          if (sub.dirty) return true;
        }
      }
    }
  }
  return false;
}

// ── Main serialize function ───────────────────────────────────────────

export function serialize(doc: Document): string {
  // Fast path: nothing changed
  if (!isDocDirty(doc)) return doc.raw;

  const parts: string[] = [];

  // Frontmatter
  if (doc.frontmatterRaw) {
    parts.push(doc.frontmatterRaw);
  }

  // Collect all nodes in order: preamble, then sections
  // We need to reconstruct, respecting that subtasks are NOT in section.body
  // (they are stored on Task.subtasks only)

  function emitNodes(nodes: Node[]): string[] {
    const lines: string[] = [];
    for (const node of nodes) {
      if (node.type === 'task') {
        const task = node as Task;
        if (!task.dirty) {
          // raw includes the task line only (subtasks have their own raw)
          lines.push(task.raw);
          for (const sub of task.subtasks) {
            lines.push(sub.dirty ? serializeTask(sub) : sub.raw);
          }
        } else {
          lines.push(serializeTask(task));
          for (const sub of task.subtasks) {
            lines.push(sub.dirty ? serializeTask(sub) : sub.raw);
          }
        }
      } else {
        lines.push(serializeNode(node));
      }
    }
    return lines;
  }

  const bodyLines: string[] = [];

  // Preamble
  bodyLines.push(...emitNodes(doc.preamble));

  // Sections
  for (const section of doc.sections) {
    bodyLines.push(section.raw);
    bodyLines.push(...emitNodes(section.body));
  }

  if (doc.frontmatterRaw) {
    return doc.frontmatterRaw + '\n' + bodyLines.join('\n');
  } else {
    return bodyLines.join('\n');
  }
}

export * from './types.js';
export { parse } from './parser.js';
export { serialize } from './serializer.js';
export {
  findSection,
  appendToSection,
  replaceSectionContent,
  findTask,
  listTasks,
  addTask,
  setTaskStatus,
  completeTask,
  moveTask,
  linkDoc,
  unlinkDoc,
  getNextTaskId,
  carryForward,
} from './operations.js';

