292	export function moveTask(doc: Document, id: string, opts: MoveOpts): Document {
293	  const result = cloneDoc(doc);
294	
295	  // Find the task and its container
296	  function findTaskInNodes(nodes: Node[], targetId: string): { task: Task; nodes: Node[]; index: number } | null {
297	    for (let i = 0; i < nodes.length; i++) {
298	      const node = nodes[i];
299	      if (node.type === 'task') {
300	        const t = node as Task;
301	        if (t.id === targetId) return { task: t, nodes, index: i };
302	        // Search subtasks
303	        for (let j = 0; j < t.subtasks.length; j++) {
304	          if (t.subtasks[j].id === targetId) {
305	            return { task: t.subtasks[j], nodes: t.subtasks, index: j };
306	          }
307	        }
308	      }
309	    }
310	    return null;
311	  }
312	
313	  function findInDoc(targetId: string): { task: Task; nodes: Node[] | Task[]; index: number } | null {
314	    let found = findTaskInNodes(result.preamble, targetId);
315	    if (found) return found;
316	    for (const sec of result.sections) {
317	      found = findTaskInNodes(sec.body, targetId);
318	      if (found) return found;
319	    }
320	    return null;
321	  }
322	
323	  if (opts.under) {
324	    const found = findInDoc(id);
325	    if (!found) throw new Error(`Task ${id} not found`);
326	    const { task, nodes, index } = found;
327	
328	    // Remove from current position
329	    (nodes as any[]).splice(index, 1);
330	
331	    // Find parent
332	    const parentFound = findInDoc(opts.under);
333	    if (!parentFound) throw new Error(`Parent task ${opts.under} not found`);
334	    const parentTask = parentFound.task;
335	
336	    // Reassign ID
337	    const newSubId = getNextTaskId(result, opts.under);
338	    task.id = newSubId;
339	    task.indent = parentTask.indent + 2;
340	    task.dirty = true;
341	    parentTask.subtasks.push(task);
342	  } else if (opts.toTop) {
343	    const found = findInDoc(id);
344	    if (!found) throw new Error(`Task ${id} not found`);
345	    const { task, nodes, index } = found;
346	
347	    // Remove from current position
348	    (nodes as any[]).splice(index, 1);
349	
350	    // Get Tasks section
351	    let taskSection = result.sections.find(s => s.heading.toLowerCase() === 'tasks');
352	    if (!taskSection) {
353	      taskSection = {
354	        heading: 'Tasks', level: 2, body: [], line: 0, raw: '## Tasks',
355	      };
356	      result.sections.push(taskSection);
357	    }
358	
359	    // Assign next top-level ID
360	    task.id = getNextTaskId(result);
361	    task.indent = 0;
362	    task.dirty = true;
363	
364	    let insertIdx = taskSection.body.length;
365	    while (insertIdx > 0 && taskSection.body[insertIdx - 1].type === 'blank') insertIdx--;
366	    taskSection.body.splice(insertIdx, 0, task);
367	  } else if (opts.before || opts.after) {
368	    const refId = opts.before ?? opts.after!;
369	    const found = findInDoc(id);
370	    const refFound = findInDoc(refId);
371	    if (!found) throw new Error(`Task ${id} not found`);
372	    if (!refFound) throw new Error(`Reference task ${refId} not found`);
373	
374	    const { task, nodes: srcNodes, index: srcIndex } = found;
375	    (srcNodes as any[]).splice(srcIndex, 1);
376	
377	    // Re-find ref after splice (indices may have shifted)
378	    const refFoundAgain = findInDoc(refId);
379	    if (!refFoundAgain) throw new Error(`Reference task ${refId} not found after splice`);
380	    const { nodes: dstNodes, index: dstIndex } = refFoundAgain;
381	
382	    const insertAt = opts.before ? dstIndex : dstIndex + 1;
383	    task.dirty = true;
384	    (dstNodes as any[]).splice(insertAt, 0, task);
385	  }
386	
387	  return result;
388	}
