390	export function linkDoc(doc: Document, taskId: string, docPath: string): Document {
391	  const result = cloneDoc(doc);
392	  const task = findTask(result, taskId);
393	  if (!task) throw new Error(`Task ${taskId} not found`);
394	  const nextNum = task.links.length > 0 ? Math.max(...task.links.map(l => l.number)) + 1 : 1;
395	  task.links.push({ path: docPath, number: nextNum });
396	  task.dirty = true;
397	  return result;
398	}
