400	export function unlinkDoc(doc: Document, taskId: string, docPath: string): Document {
401	  const result = cloneDoc(doc);
402	  const task = findTask(result, taskId);
403	  if (!task) throw new Error(`Task ${taskId} not found`);
404	  task.links = task.links.filter(l => l.path !== docPath);
405	  // Renumber remaining
406	  task.links.forEach((l, i) => (l.number = i + 1));
407	  task.dirty = true;
408	  return result;
409	}
