418	export function carryForward(
419	  source: Document,
420	  target: Document,
421	  targetDate: string,
422	): { source: Document; target: Document } {
423	  const srcResult = cloneDoc(source);
424	  const tgtResult = cloneDoc(target);
425	
426	  // Infer source date from frontmatter or raw
427	  const sourceDate: string = (srcResult.frontmatter.title as string) ?? '';
428	  const targetAlias = dateToAlias(targetDate);
429	  const sourceAlias = dateToAlias(sourceDate);
430	
431	  const incompleteSections = srcResult.sections.filter(
432	    s => s.heading.toLowerCase() === 'tasks',
433	  );
434	
435	  const incompleteStatuses: TaskStatus[] = ['todo', 'in_progress', 'urgent', 'question'];
436	
437	  function shouldCarry(task: Task): boolean {
438	    return incompleteStatuses.includes(task.status);
439	  }
440	
441	  // Get or create Tasks section in target
442	  let targetTasksSection = tgtResult.sections.find(
443	    s => s.heading.toLowerCase() === 'tasks',
444	  );
445	  if (!targetTasksSection) {
446	    targetTasksSection = {
447	      heading: 'Tasks',
448	      level: 2,
449	      body: [],
450	      line: 0,
451	      raw: '## Tasks',
452	    };
453	    tgtResult.sections.push(targetTasksSection);
454	  }
455	
456	  for (const section of incompleteSections) {
457	    for (const node of section.body) {
458	      if (node.type !== 'task') continue;
459	      const task = node as Task;
460	
461	      if (!shouldCarry(task)) continue;
462	
463	      // Mark source task as deferred
464	      task.status = 'deferred';
465	      task.isStrikethrough = true;
466	      task.forward = { path: `notes/daily/${targetDate}`, alias: targetAlias };
467	      task.dirty = true;
468	
469	      // Build new task for target
470	      const newId = getNextTaskId(tgtResult);
471	
472	      // Carry history: append source date
473	      const newHistory: Wikilink[] = [
474	        ...task.history,
475	        { path: `notes/daily/${sourceDate}`, alias: sourceAlias },
476	      ];
477	
478	      const newTask: Task = {
479	        type: 'task',
480	        line: 0,
481	        raw: '',
482	        dirty: true,
483	        id: newId,
484	        status: task.status === 'deferred' ? 'todo' : task.status,
485	        content: task.content,
486	        subtasks: [],
487	        indent: 0,
488	        links: [...task.links],
489	        history: newHistory,
490	        isLabel: task.isLabel,
491	        isStrikethrough: false,
492	      };
493	
494	      // Reset status to todo for carried tasks
495	      newTask.status = 'todo';
496	
497	      // Carry subtasks
498	      let subCounter = 1;
499	      for (const sub of task.subtasks) {
500	        if (shouldCarry(sub)) {
501	          const subHistory: Wikilink[] = [
502	            ...sub.history,
503	            { path: `notes/daily/${sourceDate}`, alias: sourceAlias },
504	          ];
505	          const newSub: Task = {
506	            type: 'task',
507	            line: 0,
508	            raw: '',
509	            dirty: true,
510	            id: `${newId}.${subCounter++}`,
511	            status: 'todo',
512	            content: sub.content,
513	            subtasks: [],
514	            indent: 2,
515	            links: [...sub.links],
516	            history: subHistory,
517	            isLabel: sub.isLabel,
518	            isStrikethrough: false,
519	          };
520	          newTask.subtasks.push(newSub);
521	        }
522	      }
523	
524	      // Also mark source subtasks as deferred
525	      for (const sub of task.subtasks) {
526	        if (shouldCarry(sub)) {
527	          sub.status = 'deferred';
528	          sub.isStrikethrough = true;
529	          sub.forward = { path: `notes/daily/${targetDate}`, alias: targetAlias };
530	          sub.dirty = true;
531	        }
532	      }
533	
534	      // Insert in target before trailing blanks
535	      let insertIdx = targetTasksSection.body.length;
536	      while (insertIdx > 0 && targetTasksSection.body[insertIdx - 1].type === 'blank') {
537	        insertIdx--;
538	      }
539	      targetTasksSection.body.splice(insertIdx, 0, newTask);
540	    }
541	  }
542	
543	  return { source: srcResult, target: tgtResult };
544	}
