import type {
  Document, Section, Node, Task, TaskStatus, TaskFilter, MoveOpts, DocLink, Wikilink,
} from './types.js';
import { parse } from './parser.js';

// ── Helpers ───────────────────────────────────────────────────────────

function cloneTask(task: Task): Task {
  return {
    ...task,
    subtasks: task.subtasks.map(cloneTask),
    links: [...task.links],
    history: [...task.history],
  };
}

function cloneNode(node: Node): Node {
  if (node.type === 'task') return cloneTask(node as Task);
  return { ...node };
}

function cloneSection(section: Section): Section {
  return {
    ...section,
    body: section.body.map(cloneNode),
  };
}

function cloneDoc(doc: Document): Document {
  return {
    ...doc,
    frontmatter: { ...doc.frontmatter },
    preamble: doc.preamble.map(cloneNode),
    sections: doc.sections.map(cloneSection),
  };
}

function tasksFromNodes(nodes: Node[]): Task[] {
  const result: Task[] = [];
  for (const node of nodes) {
    if (node.type === 'task') {
      const task = node as Task;
      result.push(task);
      result.push(...task.subtasks);
    }
  }
  return result;
}

function allTasks(doc: Document): Task[] {
  const result: Task[] = [];
  for (const node of doc.preamble) {
    if (node.type === 'task') {
      result.push(node as Task);
      result.push(...(node as Task).subtasks);
    }
  }
  for (const section of doc.sections) {
    result.push(...tasksFromNodes(section.body));
  }
  return result;
}

// ── Section operations ────────────────────────────────────────────────

export function findSection(doc: Document, name: string): Section | undefined {
  const lower = name.toLowerCase();
  return doc.sections.find(s => s.heading.toLowerCase() === lower);
}

export function appendToSection(doc: Document, name: string, content: string): Document {
  const result = cloneDoc(doc);
  let section = result.sections.find(s => s.heading.toLowerCase() === name.toLowerCase());

  if (!section) {
    // Create section at end
    const level = 2;
    const raw = `${'#'.repeat(level)} ${name}`;
    section = {
      heading: name,
      level,
      body: [],
      line: 0,
      raw,
    };
    result.sections.push(section);
  }

  // Parse new content
  const newNodes = parseNodes(content);

  // Insert before trailing blank nodes
  let insertIdx = section.body.length;
  while (insertIdx > 0 && section.body[insertIdx - 1].type === 'blank') {
    insertIdx--;
  }

  section.body.splice(insertIdx, 0, ...newNodes);
  return result;
}

export function replaceSectionContent(doc: Document, name: string, content: string): Document {
  const result = cloneDoc(doc);
  let section = result.sections.find(s => s.heading.toLowerCase() === name.toLowerCase());

  if (!section) {
    const level = 2;
    const raw = `${'#'.repeat(level)} ${name}`;
    section = {
      heading: name,
      level,
      body: [],
      line: 0,
      raw,
    };
    result.sections.push(section);
  }

  section.body = parseNodes(content);
  return result;
}

// Parse a content string into nodes (no frontmatter, no sections)
function parseNodes(content: string): Node[] {
  // Wrap in a minimal doc to reuse parse()
  const doc = parse(content);
  // Content without ## headings goes to preamble
  const nodes: Node[] = [...doc.preamble];
  for (const sec of doc.sections) {
    // Include section heading as heading node + body
    nodes.push({
      type: 'heading',
      line: sec.line,
      raw: sec.raw,
      dirty: true,
      level: sec.level,
      content: sec.heading,
    });
    nodes.push(...sec.body);
  }
  // Mark all dirty since they're new
  for (const n of nodes) {
    n.dirty = true;
    if (n.type === 'task') {
      for (const sub of (n as Task).subtasks) sub.dirty = true;
