246	  writeNote(path, serialize(updated));
247	  return confirm(`Task [${statusDef.marker}] ${statusDef.name}`, date, matched);
248	}
249	
250	// ── Edit task text ──────────────────────────────────────────────────────
251	
252	export function editTask(args: { date?: string; task: string; text: string }): string {
253	  const date = parseDate(args.date);
254	  const path = `daily/${date}.md`;
255	  if (!noteExists(path)) return notFound("daily note", date);
256	  const content = readNote(path)!;
257	  const doc = parse(content);
258	  const task = findTaskByQuery(doc, args.task);
259	
260	  if (!task) {
261	    const pending = getPendingList(doc);
262	    return `${noMatch("task", args.task, date)} ${taskFallback(pending)}`;
263	  }
264	
265	  const matched = task.content;
266	  task.content = args.text;
267	  task.dirty = true;
268	  writeNote(path, serialize(doc));
269	  return `Task updated in ${date}: "${matched}" -> "${args.text}"`;
270	}
271	
272	// ── Move task ───────────────────────────────────────────────────────────
273	
274	export function moveTask(args: { task: string; date?: string; to_date?: string; under?: string; to_top?: boolean }): string {
275	  const date = parseDate(args.date);
276	  const path = `daily/${date}.md`;
277	  if (!noteExists(path)) return notFound("daily note", date);
278	  const content = readNote(path)!;
279	  const doc = parse(content);
280	
281	  const task = findTaskByQuery(doc, args.task);
282	  if (!task) return `Task "${args.task}" not found in ${date}.`;
283	
284	  const isSubTask = task.indent > 0;
285	  const isLabel = task.isLabel;
286	
287	  // Promote sub-task to top-level
288	  if (args.to_top) {
289	    if (!isSubTask) return `Task "${args.task}" is already top-level.`;
290	    const taskText = task.content;
291	    const updated = omMoveTask(doc, task.id, { toTop: true });
292	    writeNote(path, serialize(updated));
293	    // Find new top-level task to report its ID
294	    const newDoc = parse(serialize(updated));
295	    const movedTask = findTaskByQuery(newDoc, taskText);
296	    const newId = movedTask?.id || '?';
297	    return `Promoted "${taskText}" to top-level task [${newId}] in ${date}.`;
298	  }
299	
300	  // Nest under a parent
301	  if (args.under) {
302	    const parentNum = args.under.replace(/^\[|\]$/g, '');
303	    if (isSubTask) return `Task "${args.task}" is already a sub-task. Promote it first with to_top, then nest.`;
304	    if (isLabel) return `Cannot nest a group label under another task.`;
305	    const taskText = task.content;
306	    const parentTask = findTask(doc, parentNum);
307	    if (!parentTask) return `Parent task [${parentNum}] not found.`;
308	    const updated = omMoveTask(doc, task.id, { under: parentNum });
309	    writeNote(path, serialize(updated));
310	    // Find new subtask ID
311	    const newDoc = parse(serialize(updated));
312	    const newParent = findTask(newDoc, parentNum);
313	    const newSub = newParent?.subtasks[newParent.subtasks.length - 1];
314	    const newSubId = newSub?.id || `${parentNum}.?`;
315	    return `Nested "${taskText}" under [${parentNum}] as [${newSubId}] in ${date}.`;
316	  }
317	
318	  // Move to another date
319	  if (args.to_date) {
320	    const targetDate = parseDate(args.to_date);
321	    const targetPath = `daily/${targetDate}.md`;
322	    if (!noteExists(targetPath)) return `${notFound("daily note", targetDate)} Create it first.`;
323	
324	    const targetContent = readNote(targetPath)!;
325	    const sourceDoc = parse(content);
326	    const targetDoc = parse(targetContent);
327	
328	    // Get task details before mutation
329	    const taskText = task.content;
330	    const taskId = task.id;
331	
332	    // Build the target link
333	    const targetLink = `[[notes/daily/${targetDate}|${targetDate.slice(5)}]]`;
334	    const sourceLink = `[[notes/daily/${date}|${date.slice(5)}]]`;
335	
336	    // Get next task ID in target
337	    const nextId = getNextTaskId(targetDoc);
338	
339	    // Mark source task as deferred with forward link
340	    const mutableSource = parse(content);
341	    const sourceTask = findTask(mutableSource, taskId);
342	    if (sourceTask) {
343	      sourceTask.status = 'deferred';
344	      sourceTask.isStrikethrough = true;
345	      sourceTask.forward = { path: `notes/daily/${targetDate}`, alias: targetDate.slice(5) };
346	      sourceTask.dirty = true;
347	      // Mark subtasks too
348	      for (const sub of sourceTask.subtasks) {
349	        sub.status = 'deferred';
350	        sub.isStrikethrough = true;
351	        sub.forward = { path: `notes/daily/${targetDate}`, alias: targetDate.slice(5) };
352	        sub.dirty = true;
353	      }
354	    }
355	    writeNote(path, serialize(mutableSource));
356	
357	    // Add task to target with history link
358	    let mutableTarget = parse(targetContent);
359	    const newTask: Task = {
360	      type: 'task',
361	      line: 0,
362	      raw: '',
363	      dirty: true,
364	      id: nextId,
365	      status: task.status,
366	      content: taskText,
367	      subtasks: [],
368	      indent: 0,
369	      links: [...task.links],
370	      history: [...task.history, { path: `notes/daily/${date}`, alias: date.slice(5) }],
371	      isLabel: task.isLabel,
372	      isStrikethrough: false,
373	    };
374	
375	    // Add subtasks
376	    let subCounter = 1;
377	    for (const sub of task.subtasks) {
378	      if (sub.status !== 'done' && sub.status !== 'cancelled') {
379	        newTask.subtasks.push({
380	          type: 'task',
381	          line: 0,
382	          raw: '',
383	          dirty: true,
384	          id: `${nextId}.${subCounter++}`,
385	          status: sub.status,
386	          content: sub.content,
387	          subtasks: [],
388	          indent: 2,
389	          links: [...sub.links],
390	          history: [...sub.history, { path: `notes/daily/${date}`, alias: date.slice(5) }],
391	          isLabel: sub.isLabel,
392	          isStrikethrough: false,
393	        });
394	      }
395	    }
396	
397	    // Insert into target Tasks section
398	    let targetTasksSection = mutableTarget.sections.find(s => s.heading.toLowerCase() === 'tasks');
399	    if (!targetTasksSection) {
400	      targetTasksSection = { heading: 'Tasks', level: 2, body: [], line: 0, raw: '## Tasks' };
401	      mutableTarget.sections.push(targetTasksSection);
402	    }
403	    let insertIdx = targetTasksSection.body.length;
404	    while (insertIdx > 0 && targetTasksSection.body[insertIdx - 1].type === 'blank') insertIdx--;
405	    targetTasksSection.body.splice(insertIdx, 0, newTask);
406	
407	    writeNote(targetPath, serialize(mutableTarget));
408	    return `Moved task "${args.task}" from ${date} to ${targetDate} as [${nextId}].`;
409	  }
410	
411	  return `Specify to_top, under, or to_date to move the task.`;
412	}
413	
414	// ── Link/unlink docs to tasks ──────────────────────────────────────────
415	
416	export function linkDoc(args: { date?: string; task: string; doc: string }): string {
417	  const date = parseDate(args.date);
418	  const path = ensureDaily(date);
419	  const content = readNote(path)!;
420	  const doc = parse(content);
421	
422	  // Normalize doc path
423	  const docPath = args.doc.replace(/\.md$/, "").replace(/^vault\//, "");
424	
425	  const task = findTaskByQuery(doc, args.task);
426	  if (!task) return `Task "${args.task}" not found in ${date}.`;
427	
428	  // Check if already linked
429	  if (task.links.some(l => l.path === docPath)) {
430	    return `Doc already linked to task [${args.task}] in ${date}: ${docPath}`;
431	  }
432	
433	  const updated = omLinkDoc(doc, task.id, docPath);
434	  writeNote(path, serialize(updated));
435	  return confirm(`Doc linked to task [${args.task}]`, date, docPath);
436	}
437	
438	export function unlinkDoc(args: { date?: string; task: string; doc: string }): string {
439	  const date = parseDate(args.date);
440	  const path = `daily/${date}.md`;
441	  if (!noteExists(path)) return notFound("daily note", date);
442	  const content = readNote(path)!;
443	  const doc = parse(content);
444	
445	  const docPath = args.doc.replace(/\.md$/, "").replace(/^vault\//, "");
446	
447	  const task = findTaskByQuery(doc, args.task);
448	  if (!task) return `Task "${args.task}" not found in ${date}.`;
449	
450	  if (!task.links.some(l => l.path === docPath)) {
451	    return `Doc not linked to task [${args.task}] in ${date}: ${docPath}`;
452	  }
453	
454	  const updated = omUnlinkDoc(doc, task.id, docPath);
455	  writeNote(path, serialize(updated));
456	  return confirm(`Doc unlinked from task [${args.task}]`, date, docPath);
457	}
458	
459	// ── Status groups for filtering ─────────────────────────────────────────
460	
461	const STATUS_GROUPS: Record<string, string[]> = {
462	  open: [" ", "/", "!", "?"],
463	  done: ["x", "X", ">", "-"],
464	  todo: [" "],
465	  in_progress: ["/"],
466	  urgent: ["!"],
467	  question: ["?"],
468	  completed: ["x", "X"],
469	  deferred: [">"],
470	  cancelled: ["-"],
471	};
472	
473	// ── List tasks (section only — no full note) ────────────────────────────
474	
475	export function listTasks(args: { date?: string; filter?: string; search?: string }): string {
476	  const date = parseDate(args.date);
477	  const path = `daily/${date}.md`;
478	  if (!noteExists(path)) return notFound("daily note", date);
479	  const content = readNote(path)!;
480	  const doc = parse(content);
481	  const section = omFindSection(doc, 'Tasks');
482	  if (!section || section.body.every(n => n.type === 'blank')) return notFound("tasks", date);
483	
484	  // Get raw section body as string for formatTaskLines
485	  const lines = content.split(/\r?\n/);
486	  const sectionStartLine = section.line; // 1-based line of ## heading
487	  let sectionEnd = lines.length;
488	  for (let i = sectionStartLine; i < lines.length; i++) {
489	    if (lines[i].startsWith('## ')) { sectionEnd = i; break; }
490	  }
491	  let body = lines.slice(sectionStartLine, sectionEnd).join('\n').trim();
492	
493	  if (!body) return notFound("tasks", date);
494	
495	  // Default to "open" unless explicitly "all" or no filter needed
496	  const effectiveFilter = args.filter === "all" ? undefined : (args.filter || (args.search ? undefined : "open"));
497	
498	  // Apply filters if provided
499	  if (effectiveFilter || args.search) {
500	    const allowedMarkers = effectiveFilter ? STATUS_GROUPS[effectiveFilter] : null;
501	    const searchLower = args.search?.toLowerCase();
502	    const bodyLines = body.split(/\r?\n/);
503	    const filtered: string[] = [];
504	    const added = new Set<number>();
505	
506	    for (let i = 0; i < bodyLines.length; i++) {
507	      if (added.has(i)) continue;
508	      const line = bodyLines[i];
509	
510	      const isLabel = line.match(/^\s*- \*\*\[/);
511	      if (isLabel) {
512	        let hasMatch = false;
513	        for (let j = i + 1; j < bodyLines.length; j++) {
514	          if (!bodyLines[j].match(/^\s+- /)) break;
515	          if (lineMatchesFilter(bodyLines[j], allowedMarkers, searchLower)) {
516	            hasMatch = true;
517	            break;
518	          }
519	        }
520	        if (hasMatch) {
521	          filtered.push(line);
522	          added.add(i);
523	          for (let j = i + 1; j < bodyLines.length; j++) {
524	            if (!bodyLines[j].match(/^\s+- /)) break;
525	            if (lineMatchesFilter(bodyLines[j], allowedMarkers, searchLower)) {
526	              filtered.push(bodyLines[j]);
527	              added.add(j);
528	            }
529	          }
530	        }
531	        continue;
532	      }
533	
534	      const isSub = line.match(/^\s+- /);
535	      if (isSub) continue;
536	
537	      if (lineMatchesFilter(line, allowedMarkers, searchLower)) {
538	        filtered.push(line);
539	        added.add(i);
540	        for (let j = i + 1; j < bodyLines.length; j++) {
541	          if (!bodyLines[j].match(/^\s+- /)) break;
542	          filtered.push(bodyLines[j]);
543	          added.add(j);
544	        }
545	      }
546	    }
547	
548	    if (filtered.length === 0) {
549	      const parts: string[] = [];
550	      if (effectiveFilter) parts.push(`status "${effectiveFilter}"`);
551	      if (args.search) parts.push(`"${args.search}"`);
552	      return `No tasks matching ${parts.join(" and ")} in ${date}.`;
553	    }
554	
555	    body = filtered.join("\n");
556	  }
557	
558	  const c = countItems(content);
559	  const showFilter = effectiveFilter && effectiveFilter !== "open";
560	  const label = showFilter || args.search
561	    ? `${counts(date, c)} (filtered: ${showFilter ? effectiveFilter : ""}${showFilter && args.search ? " + " : ""}${args.search ? `"${args.search}"` : ""})`
562	    : counts(date, c);
563	  return `${label}\n\n${formatTaskLines(body)}`;
564	}
565	
566	function lineMatchesFilter(line: string, allowedMarkers: string[] | null, searchLower?: string): boolean {
567	  const markerMatch = line.match(/^\s*- \[(.)\]/);
568	  if (!markerMatch) return false;
569	  if (allowedMarkers && !allowedMarkers.includes(markerMatch[1])) return false;
570	  if (searchLower && !line.toLowerCase().includes(searchLower)) return false;
571	  return true;
572	}
573	
574	// ── Summary (lightweight counts) ────────────────────────────────────────
575	
576	export function taskSummary(args: { date?: string }): string {
577	  const date = parseDate(args.date);
578	  const path = `daily/${date}.md`;
579	  if (!noteExists(path)) return notFound("daily note", date);
580	  const content = readNote(path)!;
581	  const c = countItems(content);
582	  return counts(date, c);
583	}
584	
585	// ── Tool definition ─────────────────────────────────────────────────────
586	
587	export const toolDef: ToolDefinition = {
588	  name: "obsidian_tasks",
589	  description:
590	    "Task operations on daily notes. Commands: add, complete, status, edit, move, link, unlink, list (tasks section only), summary (counts only).",
591	  inputSchema: z.object({
592	    command: z.enum(["add", "complete", "status", "edit", "move", "link", "unlink", "list", "summary"])
593	      .describe("Task command to run"),
594	    date: z.string().optional().describe("Target date (YYYY-MM-DD, 'tomorrow', 'yesterday')"),
595	    content: z.string().optional().describe("Task text (for add)"),
596	    parent: z.string().optional().describe("Parent task number for sub-tasks (for add)"),
597	    task: z.string().optional().describe("Task number or text to match"),
598	    status: z.string().optional().describe("Task status: in_progress, deferred, cancelled, urgent, question, done, todo"),
599	    text: z.string().optional().describe("New text (for edit)"),
600	    doc: z.string().optional().describe("Document path to link/unlink (for link, unlink)"),
601	    to_date: z.string().optional().describe("Move task to this date"),
602	    under: z.string().optional().describe("Nest task under this parent number"),
603	    to_top: z.boolean().optional().describe("Promote sub-task to top-level"),
604	    filter: z.string().optional().describe("Filter tasks by status: all (show everything), open (default), done, todo, in_progress, urgent, question, completed, deferred, cancelled"),
605	    search: z.string().optional().describe("Filter tasks by text search (case-insensitive)"),
606	  }),
607	  tags: ["vault", "obsidian"],
608	  execute: async (args: any) => {
609	    switch (args.command) {
610	      case "add": return { output: addTask({ content: args.content!, parent: args.parent, date: args.date }) };
611	      case "complete": return { output: completeTask({ task: args.task!, date: args.date }) };
612	      case "status": return { output: setStatus({ task: args.task!, status: args.status!, date: args.date }) };
613	      case "edit": return { output: editTask({ task: args.task!, text: args.text!, date: args.date }) };
614	      case "move": return { output: moveTask({ task: args.task!, date: args.date, to_date: args.to_date, under: args.under, to_top: args.to_top }) };
615	      case "link": return { output: linkDoc({ task: args.task!, doc: args.doc!, date: args.date }) };
616	      case "unlink": return { output: unlinkDoc({ task: args.task!, doc: args.doc!, date: args.date }) };
617	      case "list": return { output: listTasks({ date: args.date, filter: args.filter, search: args.search }) };
618	      case "summary": return { output: taskSummary({ date: args.date }) };
619	      default: return { output: `Unknown command: ${args.command}` };
620	    }
621	  },
622	};
623	
624	// ── CLI mode ────────────────────────────────────────────────────────────
625	
626	if (import.meta.main) {
627	  const argv = process.argv.slice(2);
628	  const command = argv[0];
629	
630	  if (!command || command === "--help") {
631	    console.log(`Usage: bun src/tools/obsidian/tasks.ts <command> [flags]
632	
633	Commands:
634	  add       --content <text> [--parent <num>] [--date <date>]
635	  complete  --task <num|text> [--date <date>]
636	  status    --task <num|text> --status <in_progress|deferred|cancelled|urgent|question|done|todo> [--date <date>]
637	  edit      --task <num|text> --text <new text> [--date <date>]
638	  move      --task <num|text> [--to-date <date>] [--under <num>] [--to-top] [--date <date>]
639	  link      --task <num|text> --doc <path> [--date <date>]   Link a doc to a task
640	  unlink    --task <num|text> --doc <path> [--date <date>]   Unlink a doc from a task
641	  list      [--date <date>] [--filter <all|open|done|todo|in_progress|urgent|question|completed|deferred|cancelled>] [--search <text>]
642	            Default: --filter open. Use --filter all to show everything.
643	  summary   [--date <date>]`);
644	    process.exit(0);
645	  }
646	
647	  try {
648	    let result: string;
649	    switch (command) {
650	      case "add":
651	        result = addTask({ content: flag(argv, "content") || "", parent: flag(argv, "parent"), date: flag(argv, "date") });
652	        break;
653	      case "complete":
654	        result = completeTask({ task: flag(argv, "task") || "", date: flag(argv, "date") });
655	        break;
656	      case "status":
657	        result = setStatus({ task: flag(argv, "task") || "", status: flag(argv, "status") || "", date: flag(argv, "date") });
658	        break;
659	      case "edit":
660	        result = editTask({ task: flag(argv, "task") || "", text: flag(argv, "text") || "", date: flag(argv, "date") });
661	        break;
662	      case "move":
663	        result = moveTask({
664	          task: flag(argv, "task") || "",
665	          date: flag(argv, "date"),
666	          to_date: flag(argv, "to-date"),
667	          under: flag(argv, "under"),
668	          to_top: hasFlag(argv, "to-top"),
669	        });
670	        break;
671	      case "link":
672	        result = linkDoc({ task: flag(argv, "task") || "", doc: flag(argv, "doc") || "", date: flag(argv, "date") });
673	        break;
674	      case "unlink":
675	        result = unlinkDoc({ task: flag(argv, "task") || "", doc: flag(argv, "doc") || "", date: flag(argv, "date") });
676	        break;
677	      case "list":
678	        result = listTasks({ date: flag(argv, "date"), filter: flag(argv, "filter"), search: flag(argv, "search") });
679	        break;
680	      case "summary":
681	        result = taskSummary({ date: flag(argv, "date") });
682	        break;
683	      default:
684	        console.error(`Unknown command: ${command}. Run with --help for usage.`);
685	        process.exit(1);
686	    }
687	    console.log(result);
688	  } catch (err: any) {
689	    console.error(`Error: ${err.message}`);
690	    process.exit(1);
691	  }
692	}
