#!/usr/bin/env bun
/**
 * tasks.ts — Task CRUD: add, complete, set status, move, link, unlink, list, summary
 *
 * CLI:
 *   bun src/tools/obsidian/tasks.ts add --content <text> [--parent <num>] [--date <date>]
 *   bun src/tools/obsidian/tasks.ts complete --task <num|text> [--date <date>]
 *   bun src/tools/obsidian/tasks.ts status --task <num|text> --status <status> [--date <date>]
 *   bun src/tools/obsidian/tasks.ts move --task <num|text> [--to-date <date>] [--under <num>] [--to-top] [--date <date>]
 *   bun src/tools/obsidian/tasks.ts link --task <num|text> --doc <path> [--date <date>]
 *   bun src/tools/obsidian/tasks.ts unlink --task <num|text> --doc <path> [--date <date>]
 *   bun src/tools/obsidian/tasks.ts list [--date <date>]
 *   bun src/tools/obsidian/tasks.ts summary [--date <date>]
 */

import { z } from "zod";
import type { ToolDefinition } from "../../registry/types.js";
import { parseDate } from "../../libs/dates.js";
import { readNote, writeNote, noteExists } from "../../libs/vault.js";
import {
  parse,
  serialize,
  findSection as omFindSection,
  findTask,
  listTasks as omListTasks,
  addTask as omAddTask,
  setTaskStatus as omSetTaskStatus,
  completeTask as omCompleteTask,
  moveTask as omMoveTask,
  linkDoc as omLinkDoc,
  unlinkDoc as omUnlinkDoc,
  getNextTaskId,
  carryForward as omCarryForward,
  appendToSection as omAppendToSection,
} from "../../libs/obsidian-md/index.js";
import type { Document, Task, TaskStatus } from "../../libs/obsidian-md/types.js";
import { STATUS_TO_CHAR } from "../../libs/obsidian-md/types.js";
import { confirm, notFound, noMatch, heading, counts, taskFallback, formatTaskLines } from "../../libs/format.js";
import { initializeDailyWithCarryForward, flag, hasFlag } from "./shared.js";

// ── Item counts (replaces libs/sections countItems) ─────────────────────

function countItems(content: string) {
  const doc = parse(content);
  let todo = 0, in_progress = 0, urgent = 0, question = 0;
  let done = 0, deferred = 0, cancelled = 0;
  let logs = 0, notes = 0;

  const tasksSection = omFindSection(doc, 'Tasks');
  if (tasksSection) {
    const taskNodes = omListTasks({ ...doc, sections: [tasksSection] });
    for (const t of taskNodes) {
      if (t.isLabel) continue;
      switch (t.status) {
        case 'todo': todo++; break;
        case 'in_progress': in_progress++; break;
        case 'urgent': urgent++; break;
        case 'question': question++; break;
        case 'done': done++; break;
        case 'deferred': deferred++; break;
        case 'cancelled': cancelled++; break;
      }
    }
  }

  for (const sectionName of ['Log', 'Meetings']) {
    const sec = omFindSection(doc, sectionName);
    if (sec) {
      for (const node of sec.body) {
        if (node.type === 'text' && node.raw.startsWith('- ')) logs++;
      }
    }
  }

  for (const sectionName of ['Notes', 'Session Work', 'Decisions', 'Learned']) {
    const sec = omFindSection(doc, sectionName);
    if (sec) {
      for (const node of sec.body) {
        if (node.type === 'text' && node.raw.startsWith('- ')) notes++;
      }
    }
  }

  return {
    todo, in_progress, urgent, question, done, deferred, cancelled, logs, notes,
    tasks: todo + in_progress + urgent + question,
  };
}

// ── Fuzzy task match helper ─────────────────────────────────────────────

function findTaskByQuery(doc: Document, query: string): Task | undefined {
  const cleanQuery = query.replace(/^\[|\]$/g, '');
  const numberMatch = /^\d+(\.\d+)*$/.test(cleanQuery);

  const allTasks: Task[] = [];
  for (const node of doc.preamble) {
    if (node.type === 'task') {
      const t = node as Task;
      allTasks.push(t);
      for (const sub of t.subtasks) allTasks.push(sub);
    }
  }
  for (const section of doc.sections) {
    for (const node of section.body) {
      if (node.type === 'task') {
        const t = node as Task;
        allTasks.push(t);
        for (const sub of t.subtasks) allTasks.push(sub);
      }
    }
  }

  if (numberMatch) {
    return allTasks.find(t => t.id === cleanQuery);
  }

  const queryLower = cleanQuery.toLowerCase();
  let best: Task | undefined;
  let bestLen = Infinity;
  for (const t of allTasks) {
    const contentLower = t.content.toLowerCase();
    if (contentLower.includes(queryLower) && t.content.length < bestLen) {
      best = t;
      bestLen = t.content.length;
    }
  }
  return best;
}

// ── Pending tasks list for fallback messages ────────────────────────────

function getPendingList(doc: Document): string[] {
  const tasksSection = omFindSection(doc, 'Tasks');
  if (!tasksSection) return [];
  const pending: string[] = [];
  for (const node of tasksSection.body) {
    if (node.type === 'task') {
      const t = node as Task;
      if (t.isLabel) continue;
      if (t.status === 'todo') pending.push(`- ${t.content}`);
      for (const sub of t.subtasks) {
        if (sub.status === 'todo') pending.push(`  - ${sub.content}`);
      }
    }
  }
  return pending;
}

// ── Ensure daily note exists ────────────────────────────────────────────

function ensureDaily(date: string): string {
  const path = `daily/${date}.md`;
  if (!noteExists(path)) initializeDailyWithCarryForward(date);
  return path;
}

// ── Add task ────────────────────────────────────────────────────────────

export function addTask(args: { date?: string; content: string; parent?: string }): string {
  const date = parseDate(args.date);
  const path = ensureDaily(date);
  const content = readNote(path)!;
  const doc = parse(content);

  if (args.parent) {
    const cleanParent = args.parent.replace(/^\[|\]$/g, '');
    const parentTask = findTask(doc, cleanParent);
    if (!parentTask) return `No task numbered [${cleanParent}] found.`;
    const updated = omAddTask(doc, args.content, cleanParent);
    // Find the new subtask to get its ID
    const newParent = findTask(updated, cleanParent)!;
    const newSub = newParent.subtasks[newParent.subtasks.length - 1];
    writeNote(path, serialize(updated));
    return confirm(`Sub-task added under [${cleanParent}]`, date, args.content);
  }

  const newId = getNextTaskId(doc);
  const updated = omAddTask(doc, args.content);
  writeNote(path, serialize(updated));
  return confirm(`Task [${newId}] added`, date, args.content);
}

// ── Complete task ───────────────────────────────────────────────────────

export function completeTask(args: { date?: string; task: string }): string {
  const date = parseDate(args.date);
  const path = `daily/${date}.md`;
  if (!noteExists(path)) return notFound("daily note", date);
  const content = readNote(path)!;
  const doc = parse(content);
  const task = findTaskByQuery(doc, args.task);

  if (!task) {
    const pending = getPendingList(doc);
    if (pending.length === 0) return notFound("pending tasks", date);
    return `${noMatch("task", args.task, date)} ${taskFallback(pending)}`;
  }

  // Old toggleTask only toggled [ ] tasks
  if (task.status !== 'todo') {
    const pending = getPendingList(doc);
    if (pending.length === 0) return notFound("pending tasks", date);
    return `${noMatch("task", args.task, date)} ${taskFallback(pending)}`;
  }

  const matched = task.content;
  const updated = omCompleteTask(doc, task.id);
  writeNote(path, serialize(updated));
  return confirm("Task completed", date, matched);
}

// ── Set status ──────────────────────────────────────────────────────────

const TASK_STATUSES: Record<string, { marker: string; name: string; type: string }> = {
  in_progress: { marker: '/', name: 'In Progress', type: 'IN_PROGRESS' },
  deferred:    { marker: '>', name: 'Deferred', type: 'DONE' },
  cancelled:   { marker: '-', name: 'Cancelled', type: 'CANCELLED' },
  urgent:      { marker: '!', name: 'Urgent', type: 'TODO' },
  question:    { marker: '?', name: 'Question', type: 'TODO' },
  done:        { marker: 'x', name: 'Done', type: 'DONE' },
  todo:        { marker: ' ', name: 'Todo', type: 'TODO' },
};

export function setStatus(args: { date?: string; task: string; status: string }): string {
  const statusDef = TASK_STATUSES[args.status];
  if (!statusDef) {
    const valid = Object.entries(TASK_STATUSES).map(([k, v]) => `${k} [${v.marker}]`).join(", ");
    return `Unknown status "${args.status}". Valid: ${valid}`;
  }
  const date = parseDate(args.date);
  const path = `daily/${date}.md`;
  if (!noteExists(path)) return notFound("daily note", date);
  const content = readNote(path)!;
  const doc = parse(content);
  const task = findTaskByQuery(doc, args.task);

  if (!task) {
    const pending = getPendingList(doc);
    if (pending.length === 0) return notFound("tasks", date);
    return `${noMatch("task", args.task, date)} ${taskFallback(pending)}`;
  }

  const matched = task.content;
  const updated = omSetTaskStatus(doc, task.id, args.status as TaskStatus);
  writeNote(path, serialize(updated));
  return confirm(`Task [${statusDef.marker}] ${statusDef.name}`, date, matched);
}

// ── Edit task text ──────────────────────────────────────────────────────

export function editTask(args: { date?: string; task: string; text: string }): string {
  const date = parseDate(args.date);
  const path = `daily/${date}.md`;
  if (!noteExists(path)) return notFound("daily note", date);
  const content = readNote(path)!;
  const doc = parse(content);
  const task = findTaskByQuery(doc, args.task);

  if (!task) {
    const pending = getPendingList(doc);
    return `${noMatch("task", args.task, date)} ${taskFallback(pending)}`;
  }

  const matched = task.content;
  task.content = args.text;
  task.dirty = true;
  writeNote(path, serialize(doc));
  return `Task updated in ${date}: "${matched}" -> "${args.text}"`;
}

// ── Move task ───────────────────────────────────────────────────────────

export function moveTask(args: { task: string; date?: string; to_date?: string; under?: string; to_top?: boolean }): string {
  const date = parseDate(args.date);
  const path = `daily/${date}.md`;
  if (!noteExists(path)) return notFound("daily note", date);
  const content = readNote(path)!;
  const doc = parse(content);

  const task = findTaskByQuery(doc, args.task);
  if (!task) return `Task "${args.task}" not found in ${date}.`;

  const isSubTask = task.indent > 0;
  const isLabel = task.isLabel;

  // Promote sub-task to top-level
  if (args.to_top) {
    if (!isSubTask) return `Task "${args.task}" is already top-level.`;
    const taskText = task.content;
    const updated = omMoveTask(doc, task.id, { toTop: true });
    writeNote(path, serialize(updated));
    // Find new top-level task to report its ID
    const newDoc = parse(serialize(updated));
    const movedTask = findTaskByQuery(newDoc, taskText);
    const newId = movedTask?.id || '?';
    return `Promoted "${taskText}" to top-level task [${newId}] in ${date}.`;
  }

  // Nest under a parent
  if (args.under) {
    const parentNum = args.under.replace(/^\[|\]$/g, '');
    if (isSubTask) return `Task "${args.task}" is already a sub-task. Promote it first with to_top, then nest.`;
    if (isLabel) return `Cannot nest a group label under another task.`;
    const taskText = task.content;
    const parentTask = findTask(doc, parentNum);
    if (!parentTask) return `Parent task [${parentNum}] not found.`;
    const updated = omMoveTask(doc, task.id, { under: parentNum });
    writeNote(path, serialize(updated));
    // Find new subtask ID
    const newDoc = parse(serialize(updated));
    const newParent = findTask(newDoc, parentNum);
    const newSub = newParent?.subtasks[newParent.subtasks.length - 1];
    const newSubId = newSub?.id || `${parentNum}.?`;
    return `Nested "${taskText}" under [${parentNum}] as [${newSubId}] in ${date}.`;
  }

  // Move to another date
  if (args.to_date) {
    const targetDate = parseDate(args.to_date);
    const targetPath = `daily/${targetDate}.md`;
    if (!noteExists(targetPath)) return `${notFound("daily note", targetDate)} Create it first.`;

    const targetContent = readNote(targetPath)!;
    const sourceDoc = parse(content);
    const targetDoc = parse(targetContent);

    // Get task details before mutation
    const taskText = task.content;
    const taskId = task.id;

    // Build the target link
    const targetLink = `[[notes/daily/${targetDate}|${targetDate.slice(5)}]]`;
    const sourceLink = `[[notes/daily/${date}|${date.slice(5)}]]`;

    // Get next task ID in target
    const nextId = getNextTaskId(targetDoc);

    // Mark source task as deferred with forward link
    const mutableSource = parse(content);
    const sourceTask = findTask(mutableSource, taskId);
    if (sourceTask) {
      sourceTask.status = 'deferred';
      sourceTask.isStrikethrough = true;
      sourceTask.forward = { path: `notes/daily/${targetDate}`, alias: targetDate.slice(5) };
      sourceTask.dirty = true;
      // Mark subtasks too
      for (const sub of sourceTask.subtasks) {
        sub.status = 'deferred';
        sub.isStrikethrough = true;
        sub.forward = { path: `notes/daily/${targetDate}`, alias: targetDate.slice(5) };
        sub.dirty = true;
      }
    }
    writeNote(path, serialize(mutableSource));

    // Add task to target with history link
    let mutableTarget = parse(targetContent);
    const newTask: Task = {
      type: 'task',
      line: 0,
      raw: '',
      dirty: true,
      id: nextId,
      status: task.status,
      content: taskText,
      subtasks: [],
      indent: 0,
      links: [...task.links],
      history: [...task.history, { path: `notes/daily/${date}`, alias: date.slice(5) }],
      isLabel: task.isLabel,
      isStrikethrough: false,
    };

    // Add subtasks
    let subCounter = 1;
    for (const sub of task.subtasks) {
      if (sub.status !== 'done' && sub.status !== 'cancelled') {
        newTask.subtasks.push({
          type: 'task',
          line: 0,
          raw: '',
          dirty: true,
          id: `${nextId}.${subCounter++}`,
          status: sub.status,
          content: sub.content,
          subtasks: [],
          indent: 2,
          links: [...sub.links],
          history: [...sub.history, { path: `notes/daily/${date}`, alias: date.slice(5) }],
          isLabel: sub.isLabel,
          isStrikethrough: false,
        });
      }
    }

    // Insert into target Tasks section
    let targetTasksSection = mutableTarget.sections.find(s => s.heading.toLowerCase() === 'tasks');
    if (!targetTasksSection) {
      targetTasksSection = { heading: 'Tasks', level: 2, body: [], line: 0, raw: '## Tasks' };
      mutableTarget.sections.push(targetTasksSection);
    }
    let insertIdx = targetTasksSection.body.length;
    while (insertIdx > 0 && targetTasksSection.body[insertIdx - 1].type === 'blank') insertIdx--;
    targetTasksSection.body.splice(insertIdx, 0, newTask);

    writeNote(targetPath, serialize(mutableTarget));
    return `Moved task "${args.task}" from ${date} to ${targetDate} as [${nextId}].`;
  }

  return `Specify to_top, under, or to_date to move the task.`;
}

// ── Link/unlink docs to tasks ──────────────────────────────────────────

export function linkDoc(args: { date?: string; task: string; doc: string }): string {
  const date = parseDate(args.date);
  const path = ensureDaily(date);
  const content = readNote(path)!;
  const doc = parse(content);

  // Normalize doc path
  const docPath = args.doc.replace(/\.md$/, "").replace(/^vault\//, "");

  const task = findTaskByQuery(doc, args.task);
  if (!task) return `Task "${args.task}" not found in ${date}.`;

  // Check if already linked
  if (task.links.some(l => l.path === docPath)) {
    return `Doc already linked to task [${args.task}] in ${date}: ${docPath}`;
  }

  const updated = omLinkDoc(doc, task.id, docPath);
  writeNote(path, serialize(updated));
  return confirm(`Doc linked to task [${args.task}]`, date, docPath);
}

export function unlinkDoc(args: { date?: string; task: string; doc: string }): string {
  const date = parseDate(args.date);
  const path = `daily/${date}.md`;
  if (!noteExists(path)) return notFound("daily note", date);
  const content = readNote(path)!;
  const doc = parse(content);

  const docPath = args.doc.replace(/\.md$/, "").replace(/^vault\//, "");

  const task = findTaskByQuery(doc, args.task);
  if (!task) return `Task "${args.task}" not found in ${date}.`;

  if (!task.links.some(l => l.path === docPath)) {
    return `Doc not linked to task [${args.task}] in ${date}: ${docPath}`;
  }

  const updated = omUnlinkDoc(doc, task.id, docPath);
  writeNote(path, serialize(updated));
  return confirm(`Doc unlinked from task [${args.task}]`, date, docPath);
}

// ── Status groups for filtering ─────────────────────────────────────────

const STATUS_GROUPS: Record<string, string[]> = {
  open: [" ", "/", "!", "?"],
  done: ["x", "X", ">", "-"],
  todo: [" "],
  in_progress: ["/"],
  urgent: ["!"],
  question: ["?"],
  completed: ["x", "X"],
  deferred: [">"],
  cancelled: ["-"],
};

// ── List tasks (section only — no full note) ────────────────────────────

export function listTasks(args: { date?: string; filter?: string; search?: string }): string {
  const date = parseDate(args.date);
  const path = `daily/${date}.md`;
  if (!noteExists(path)) return notFound("daily note", date);
  const content = readNote(path)!;
  const doc = parse(content);
  const section = omFindSection(doc, 'Tasks');
  if (!section || section.body.every(n => n.type === 'blank')) return notFound("tasks", date);

  // Get raw section body as string for formatTaskLines
  const lines = content.split(/\r?\n/);
  const sectionStartLine = section.line; // 1-based line of ## heading
  let sectionEnd = lines.length;
  for (let i = sectionStartLine; i < lines.length; i++) {
    if (lines[i].startsWith('## ')) { sectionEnd = i; break; }
  }
  let body = lines.slice(sectionStartLine, sectionEnd).join('\n').trim();

  if (!body) return notFound("tasks", date);

  // Default to "open" unless explicitly "all" or no filter needed
  const effectiveFilter = args.filter === "all" ? undefined : (args.filter || (args.search ? undefined : "open"));

  // Apply filters if provided
  if (effectiveFilter || args.search) {
    const allowedMarkers = effectiveFilter ? STATUS_GROUPS[effectiveFilter] : null;
    const searchLower = args.search?.toLowerCase();
    const bodyLines = body.split(/\r?\n/);
    const filtered: string[] = [];
    const added = new Set<number>();

    for (let i = 0; i < bodyLines.length; i++) {
      if (added.has(i)) continue;
      const line = bodyLines[i];

      const isLabel = line.match(/^\s*- \*\*\[/);
      if (isLabel) {
        let hasMatch = false;
        for (let j = i + 1; j < bodyLines.length; j++) {
          if (!bodyLines[j].match(/^\s+- /)) break;
          if (lineMatchesFilter(bodyLines[j], allowedMarkers, searchLower)) {
            hasMatch = true;
            break;
          }
        }
        if (hasMatch) {
          filtered.push(line);
          added.add(i);
          for (let j = i + 1; j < bodyLines.length; j++) {
            if (!bodyLines[j].match(/^\s+- /)) break;
            if (lineMatchesFilter(bodyLines[j], allowedMarkers, searchLower)) {
              filtered.push(bodyLines[j]);
              added.add(j);
            }
          }
        }
        continue;
      }

      const isSub = line.match(/^\s+- /);
      if (isSub) continue;

      if (lineMatchesFilter(line, allowedMarkers, searchLower)) {
        filtered.push(line);
        added.add(i);
        for (let j = i + 1; j < bodyLines.length; j++) {
          if (!bodyLines[j].match(/^\s+- /)) break;
          filtered.push(bodyLines[j]);
          added.add(j);
        }
      }
    }

    if (filtered.length === 0) {
      const parts: string[] = [];
      if (effectiveFilter) parts.push(`status "${effectiveFilter}"`);
      if (args.search) parts.push(`"${args.search}"`);
      return `No tasks matching ${parts.join(" and ")} in ${date}.`;
    }

    body = filtered.join("\n");
  }

  const c = countItems(content);
  const showFilter = effectiveFilter && effectiveFilter !== "open";
  const label = showFilter || args.search
    ? `${counts(date, c)} (filtered: ${showFilter ? effectiveFilter : ""}${showFilter && args.search ? " + " : ""}${args.search ? `"${args.search}"` : ""})`
    : counts(date, c);
  return `${label}\n\n${formatTaskLines(body)}`;
}

function lineMatchesFilter(line: string, allowedMarkers: string[] | null, searchLower?: string): boolean {
  const markerMatch = line.match(/^\s*- \[(.)\]/);
  if (!markerMatch) return false;
  if (allowedMarkers && !allowedMarkers.includes(markerMatch[1])) return false;
  if (searchLower && !line.toLowerCase().includes(searchLower)) return false;
  return true;
}

// ── Summary (lightweight counts) ────────────────────────────────────────

export function taskSummary(args: { date?: string }): string {
  const date = parseDate(args.date);
  const path = `daily/${date}.md`;
  if (!noteExists(path)) return notFound("daily note", date);
  const content = readNote(path)!;
  const c = countItems(content);
  return counts(date, c);
}

// ── Tool definition ─────────────────────────────────────────────────────

export const toolDef: ToolDefinition = {
  name: "obsidian_tasks",
  description:
    "Task operations on daily notes. Commands: add, complete, status, edit, move, link, unlink, list (tasks section only), summary (counts only).",
  inputSchema: z.object({
    command: z.enum(["add", "complete", "status", "edit", "move", "link", "unlink", "list", "summary"])
      .describe("Task command to run"),
    date: z.string().optional().describe("Target date (YYYY-MM-DD, 'tomorrow', 'yesterday')"),
    content: z.string().optional().describe("Task text (for add)"),
    parent: z.string().optional().describe("Parent task number for sub-tasks (for add)"),
    task: z.string().optional().describe("Task number or text to match"),
    status: z.string().optional().describe("Task status: in_progress, deferred, cancelled, urgent, question, done, todo"),
    text: z.string().optional().describe("New text (for edit)"),
    doc: z.string().optional().describe("Document path to link/unlink (for link, unlink)"),
    to_date: z.string().optional().describe("Move task to this date"),
    under: z.string().optional().describe("Nest task under this parent number"),
    to_top: z.boolean().optional().describe("Promote sub-task to top-level"),
    filter: z.string().optional().describe("Filter tasks by status: all (show everything), open (default), done, todo, in_progress, urgent, question, completed, deferred, cancelled"),
    search: z.string().optional().describe("Filter tasks by text search (case-insensitive)"),
  }),
  tags: ["vault", "obsidian"],
  execute: async (args: any) => {
    switch (args.command) {
      case "add": return { output: addTask({ content: args.content!, parent: args.parent, date: args.date }) };
      case "complete": return { output: completeTask({ task: args.task!, date: args.date }) };
      case "status": return { output: setStatus({ task: args.task!, status: args.status!, date: args.date }) };
      case "edit": return { output: editTask({ task: args.task!, text: args.text!, date: args.date }) };
      case "move": return { output: moveTask({ task: args.task!, date: args.date, to_date: args.to_date, under: args.under, to_top: args.to_top }) };
      case "link": return { output: linkDoc({ task: args.task!, doc: args.doc!, date: args.date }) };
      case "unlink": return { output: unlinkDoc({ task: args.task!, doc: args.doc!, date: args.date }) };
      case "list": return { output: listTasks({ date: args.date, filter: args.filter, search: args.search }) };
      case "summary": return { output: taskSummary({ date: args.date }) };
      default: return { output: `Unknown command: ${args.command}` };
    }
  },
};

// ── CLI mode ────────────────────────────────────────────────────────────

if (import.meta.main) {
  const argv = process.argv.slice(2);
  const command = argv[0];

  if (!command || command === "--help") {
    console.log(`Usage: bun src/tools/obsidian/tasks.ts <command> [flags]

Commands:
  add       --content <text> [--parent <num>] [--date <date>]
  complete  --task <num|text> [--date <date>]
  status    --task <num|text> --status <in_progress|deferred|cancelled|urgent|question|done|todo> [--date <date>]
  edit      --task <num|text> --text <new text> [--date <date>]
  move      --task <num|text> [--to-date <date>] [--under <num>] [--to-top] [--date <date>]
  link      --task <num|text> --doc <path> [--date <date>]   Link a doc to a task
  unlink    --task <num|text> --doc <path> [--date <date>]   Unlink a doc from a task
  list      [--date <date>] [--filter <all|open|done|todo|in_progress|urgent|question|completed|deferred|cancelled>] [--search <text>]
            Default: --filter open. Use --filter all to show everything.
  summary   [--date <date>]`);
    process.exit(0);
  }

  try {
    let result: string;
    switch (command) {
      case "add":
        result = addTask({ content: flag(argv, "content") || "", parent: flag(argv, "parent"), date: flag(argv, "date") });
        break;
      case "complete":
        result = completeTask({ task: flag(argv, "task") || "", date: flag(argv, "date") });
        break;
      case "status":
        result = setStatus({ task: flag(argv, "task") || "", status: flag(argv, "status") || "", date: flag(argv, "date") });
        break;
      case "edit":
        result = editTask({ task: flag(argv, "task") || "", text: flag(argv, "text") || "", date: flag(argv, "date") });
        break;
      case "move":
        result = moveTask({
          task: flag(argv, "task") || "",
          date: flag(argv, "date"),
          to_date: flag(argv, "to-date"),
          under: flag(argv, "under"),
          to_top: hasFlag(argv, "to-top"),
        });
        break;
      case "link":
        result = linkDoc({ task: flag(argv, "task") || "", doc: flag(argv, "doc") || "", date: flag(argv, "date") });
        break;
      case "unlink":
        result = unlinkDoc({ task: flag(argv, "task") || "", doc: flag(argv, "doc") || "", date: flag(argv, "date") });
        break;
      case "list":
        result = listTasks({ date: flag(argv, "date"), filter: flag(argv, "filter"), search: flag(argv, "search") });
        break;
      case "summary":
        result = taskSummary({ date: flag(argv, "date") });
        break;
      default:
        console.error(`Unknown command: ${command}. Run with --help for usage.`);
        process.exit(1);
    }
    console.log(result);
  } catch (err: any) {
    console.error(`Error: ${err.message}`);
    process.exit(1);
  }
}

