#!/usr/bin/env bun
/**
 * daily.ts — Daily note lifecycle: create, get, status, carry-forward
 *
 * CLI:
 *   bun src/tools/obsidian/daily.ts [--date <date>]                     — status (default)
 *   bun src/tools/obsidian/daily.ts --action add_task --content <text>  — add task (delegates to tasks.ts)
 *   bun src/tools/obsidian/daily.ts --action add_note --content <text>  — add note
 *   bun src/tools/obsidian/daily.ts --action add_log --content <text>   — add log entry
 */

import { z } from "zod";
import type { ToolDefinition } from "../../registry/types.js";
import { parseDate } from "../../libs/dates.js";
import { readNote, writeNote, noteExists } from "../../libs/vault.js";
import {
  parse,
  serialize,
  appendToSection as omAppendToSection,
  listTasks as omListTasks,
  findSection as omFindSection,
} from "../../libs/obsidian-md/index.js";
import type { Task } from "../../libs/obsidian-md/types.js";
import { confirm, notFound, dailyStatus, timeNow } from "../../libs/format.js";
import { initializeDailyWithCarryForward, flag } from "./shared.js";
import { addTask } from "./tasks.js";

// ── Handler ─────────────────────────────────────────────────────────────

export function daily(args: { date?: string; action?: string; content?: string; parent?: string }): string {
  const date = parseDate(args.date);
  const path = `daily/${date}.md`;
  const isNew = !noteExists(path);
  let carryMsg = "";
  if (isNew) {
    carryMsg = initializeDailyWithCarryForward(date);
  }
  if (!args.action || args.action === "status") {
    const note = readNote(path)!;
    const c = buildCounts(note);
    const status = dailyStatus(date, c);
    const carry = carryMsg ? `\n${carryMsg}\n` : "";
    return `${status}${carry}\n${note}`;
  }
  if (!args.content) return `Error: action "${args.action}" requires content.`;

  switch (args.action) {
    case "add_task":
      return addTask({ date: args.date, content: args.content, parent: args.parent });
    case "add_note": {
      const note = readNote(path)!;
      const doc = parse(note);
      const updated = omAppendToSection(doc, "Notes", `- ${args.content}`);
      writeNote(path, serialize(updated));
      return confirm("Note added", date, args.content);
    }
    case "add_log": {
      const note = readNote(path)!;
      const doc = parse(note);
      const updated = omAppendToSection(doc, "Log", `- ${timeNow()} — ${args.content}`);
      writeNote(path, serialize(updated));
      return confirm("Log entry added", date, args.content);
    }
    default:
      return `Unknown action: ${args.action}. Use: status, add_task, add_note, add_log.`;
  }
}

// ── Build counts using AST ──────────────────────────────────────────────

function buildCounts(note: string) {
  const doc = parse(note);

  let todo = 0, in_progress = 0, urgent = 0, question = 0;
  let done = 0, deferred = 0, cancelled = 0;
  let logs = 0, notes = 0;

  const tasksSection = omFindSection(doc, 'Tasks');
  if (tasksSection) {
    const allTasks = omListTasks({ ...doc, sections: [tasksSection] });
    for (const t of allTasks) {
      if (t.isLabel) continue;
      switch (t.status) {
        case 'todo': todo++; break;
        case 'in_progress': in_progress++; break;
        case 'urgent': urgent++; break;
        case 'question': question++; break;
        case 'done': done++; break;
        case 'deferred': deferred++; break;
        case 'cancelled': cancelled++; break;
      }
    }
  }

  for (const sectionName of ['Log', 'Meetings']) {
    const sec = omFindSection(doc, sectionName);
    if (sec) {
      for (const node of sec.body) {
        if (node.type === 'text' && node.raw.startsWith('- ')) logs++;
      }
    }
  }

  for (const sectionName of ['Notes', 'Session Work', 'Decisions', 'Learned']) {
    const sec = omFindSection(doc, sectionName);
    if (sec) {
      for (const node of sec.body) {
        if (node.type === 'text' && node.raw.startsWith('- ')) notes++;
      }
    }
  }

  return {
    todo, in_progress, urgent, question, done, deferred, cancelled, logs, notes,
    tasks: todo + in_progress + urgent + question,
  };
}

export function getDaily(args: { date?: string }): string {
  const date = parseDate(args.date);
  const content = readNote(`daily/${date}.md`);
  if (!content) return notFound("daily note", date);
  return content;
}

// ── Tool definition ─────────────────────────────────────────────────────

export const toolDef: ToolDefinition = {
  name: "obsidian_daily",
  description: "Create or read daily notes. Actions: status (default, returns full note), add_task, add_note, add_log.",
  inputSchema: z.object({
    date: z.string().optional().describe("Target date (YYYY-MM-DD, 'tomorrow', 'yesterday'). Defaults to today."),
    action: z.enum(["status", "add_task", "add_note", "add_log"]).optional().describe("Action to perform."),
    content: z.string().optional().describe("Content to add (required for add_task, add_note, add_log)."),
    parent: z.string().optional().describe("For add_task: parent task number to add sub-task under (e.g., '3')."),
  }),
  tags: ["vault", "obsidian"],
  execute: async (args: any) => ({ output: daily(args) }),
};

// ── CLI mode ────────────────────────────────────────────────────────────

if (import.meta.main) {
  const argv = process.argv.slice(2);
  const command = argv[0];

  // Support `daily get` as shorthand
  if (command === "get") {
    try {
      console.log(getDaily({ date: flag(argv, "date") }));
    } catch (err: any) {
      console.error(`Error: ${err.message}`);
      process.exit(1);
    }
  } else {
    try {
      console.log(daily({
        date: flag(argv, "date"),
        action: flag(argv, "action"),
        content: flag(argv, "content"),
        parent: flag(argv, "parent"),
      }));
    } catch (err: any) {
      console.error(`Error: ${err.message}`);
      process.exit(1);
    }
  }
}

