2	/**
3	 * sections.ts — Section-level read/append/edit for daily notes
4	 *
5	 * Avoids loading full notes into context — operates on specific sections only.
6	 *
7	 * CLI:
8	 *   bun src/tools/obsidian/sections.ts read --name <section> [--date <date>]
9	 *   bun src/tools/obsidian/sections.ts append --name <section> --content <text> [--date <date>]
10	 *   bun src/tools/obsidian/sections.ts add-decision --content <text> [--date <date>]
11	 *   bun src/tools/obsidian/sections.ts add-learned --content <text> [--date <date>]
12	 *   bun src/tools/obsidian/sections.ts add-tomorrow --content <text> [--date <date>]
13	 *   bun src/tools/obsidian/sections.ts add-session --content <text> [--date <date>]
14	 *   bun src/tools/obsidian/sections.ts add-note --content <text> [--date <date>]
15	 *   bun src/tools/obsidian/sections.ts add-log --content <text> [--date <date>]
16	 *   bun src/tools/obsidian/sections.ts edit --name <section> [--match <text>] --text <new> [--date <date>] [--file <path>]
17	 */
18	
19	import { z } from "zod";
20	import type { ToolDefinition } from "../../registry/types.js";
21	import { parseDate } from "../../libs/dates.js";
22	import { readNote, writeNote, noteExists } from "../../libs/vault.js";
23	import {
24	  parse,
25	  serialize,
26	  findSection as omFindSection,
27	  appendToSection as omAppendToSection,
28	  replaceSectionContent as omReplaceSectionContent,
29	} from "../../libs/obsidian-md/index.js";
30	import { confirm, notFound, empty, timeNow } from "../../libs/format.js";
31	import { initializeDailyWithCarryForward, flag } from "./shared.js";
32	
33	// ── Ensure daily note exists ────────────────────────────────────────────
34	
35	function ensureDaily(date: string): string {
36	  const path = `daily/${date}.md`;
37	  if (!noteExists(path)) initializeDailyWithCarryForward(date);
38	  return path;
39	}
40	
41	// ── Read a section ──────────────────────────────────────────────────────
42	
43	export function readSection(args: { name: string; date?: string }): string {
44	  const date = parseDate(args.date);
45	  const path = `daily/${date}.md`;
46	  if (!noteExists(path)) return notFound("daily note", date);
47	  const content = readNote(path)!;
48	  const doc = parse(content);
49	  const section = omFindSection(doc, args.name);
50	  if (!section) return notFound(`section "## ${args.name}"`, date);
51	
52	  // Return raw section body as string (same as old code)
53	  const lines = content.split(/\r?\n/);
54	  const sectionStartLine = section.line; // 1-based line of ## heading
55	  let sectionEnd = lines.length;
56	  for (let i = sectionStartLine; i < lines.length; i++) {
57	    if (lines[i].startsWith('## ')) { sectionEnd = i; break; }
58	  }
59	  const body = lines.slice(sectionStartLine, sectionEnd).join('\n').trim();
60	  if (!body) return empty(args.name, date);
61	  return body;
62	}
63	
64	// ── Append to a section ─────────────────────────────────────────────────
65	
66	export function appendSection(args: { name: string; content: string; date?: string; prefix?: string }): string {
67	  const date = parseDate(args.date);
68	  const path = ensureDaily(date);
69	  const note = readNote(path)!;
70	  const line = args.prefix ? `${args.prefix}${args.content}` : `- ${args.content}`;
71	  const doc = parse(note);
72	  const updated = omAppendToSection(doc, args.name, line);
73	  writeNote(path, serialize(updated));
74	  return confirm(`Added to ## ${args.name}`, date, args.content);
75	}
76	
77	// ── Convenience appenders ───────────────────────────────────────────────
78	
79	export function addDecision(args: { content: string; date?: string }): string {
80	  return appendSection({ name: "Decisions", content: args.content, date: args.date });
81	}
82	
83	export function addLearned(args: { content: string; date?: string }): string {
84	  return appendSection({ name: "Learned", content: args.content, date: args.date });
85	}
86	
87	export function addTomorrow(args: { content: string; date?: string }): string {
88	  return appendSection({ name: "Tomorrow", content: args.content, date: args.date, prefix: "- [ ] " });
89	}
90	
91	export function addSession(args: { content: string; date?: string }): string {
92	  const date = parseDate(args.date);
93	  const path = ensureDaily(date);
94	  const note = readNote(path)!;
95	  const doc = parse(note);
96	  const updated = omAppendToSection(doc, "Session Work", `### ${args.content}`);
97	  writeNote(path, serialize(updated));
98	  return confirm("Session heading added", date, `### ${args.content}`);
99	}
100	
101	export function addNote(args: { content: string; date?: string }): string {
102	  return appendSection({ name: "Notes", content: args.content, date: args.date });
103	}
104	
105	export function addLog(args: { content: string; date?: string }): string {
106	  return appendSection({ name: "Log", content: `${timeNow()} — ${args.content}`, date: args.date });
107	}
108	
109	// ── Edit section content ────────────────────────────────────────────────
110	
111	export function edit(args: { date?: string; file?: string; section?: string; match?: string; text: string }): string {
112	  let path: string;
113	  if (args.file) {
114	    path = args.file.replace(/^vault\/notes\//, "");
115	    if (!path.endsWith(".md")) path += ".md";
116	  } else {
117	    const date = parseDate(args.date);
118	    path = `daily/${date}.md`;
119	  }
120	
121	  if (!noteExists(path)) return notFound("note", path);
122	  const content = readNote(path)!;
123	  const doc = parse(content);
124	
125	  if (args.section && args.match) {
126	    const sec = omFindSection(doc, args.section);
127	    if (!sec) return `No line matching "${args.match}" in ## ${args.section}.`;
128	
129	    const matchLower = args.match.toLowerCase();
130	    for (const node of sec.body) {
131	      if (node.raw.toLowerCase().includes(matchLower)) {
132	        const matched = node.raw.trim();
133	        const prefix = node.raw.match(/^(\s*- (?:\[[ x]\] )?)/i);
134	        if (prefix) {
135	          node.raw = `${prefix[1]}${args.text}`;
136	        } else {
137	          node.raw = args.text;
138	        }
139	        node.dirty = true;
140	        writeNote(path, serialize(doc));
141	        return `Updated in ## ${args.section}: "${matched}" -> "${args.text}"`;
142	      }
143	    }
144	    return `No line matching "${args.match}" in ## ${args.section}.`;
145	  }
146	
147	  if (args.section && !args.match) {
148	    const sec = omFindSection(doc, args.section);
149	    if (!sec) return notFound(`section "## ${args.section}"`, path);
150	    const updated = omReplaceSectionContent(doc, args.section, args.text);
151	    writeNote(path, serialize(updated));
152	    return `Replaced content of ## ${args.section} in ${path}`;
153	  }
154	
155	  if (args.match) {
156	    const matchLower = args.match.toLowerCase();
157	    const lines = content.split(/\r?\n/);
158	    for (let i = 0; i < lines.length; i++) {
159	      if (lines[i].toLowerCase().includes(matchLower)) {
160	        const matched = lines[i].trim();
161	        lines[i] = args.text;
162	        writeNote(path, lines.join("\n"));
163	        return `Updated: "${matched}" -> "${args.text}"`;
164	      }
165	    }
166	    return `No line matching "${args.match}" in ${path}.`;
167	  }
168	
169	  return `Specify section (with optional match), or match alone.`;
170	}
171	
172	// ── Tool definition ─────────────────────────────────────────────────────
173	
174	export const toolDef: ToolDefinition = {
175	  name: "obsidian_sections",
176	  description:
177	    "Section-level operations on daily notes. Commands: read (one section only), " +
178	    "append (generic), add-decision, add-learned, add-tomorrow, add-session, add-note, add-log, " +
179	    "edit (section content by match or replace).",
180	  inputSchema: z.object({
181	    command: z.enum(["read", "append", "add-decision", "add-learned", "add-tomorrow", "add-session", "add-note", "add-log", "edit"])
182	      .describe("Section command to run"),
183	    name: z.string().optional().describe("Section name (e.g., 'Decisions', 'Learned', 'Tomorrow')"),
184	    content: z.string().optional().describe("Content to add"),
185	    date: z.string().optional().describe("Target date (YYYY-MM-DD, 'tomorrow', 'yesterday')"),
186	    file: z.string().optional().describe("File path for edit (overrides date)"),
187	    section: z.string().optional().describe("Section name for edit"),
188	    match: z.string().optional().describe("Text to find for edit"),
189	    text: z.string().optional().describe("New text for edit"),
190	  }),
191	  tags: ["vault", "obsidian"],
192	  execute: async (args: any) => {
193	    switch (args.command) {
194	      case "read": return { output: readSection({ name: args.name!, date: args.date }) };
195	      case "append": return { output: appendSection({ name: args.name!, content: args.content!, date: args.date }) };
196	      case "add-decision": return { output: addDecision({ content: args.content!, date: args.date }) };
197	      case "add-learned": return { output: addLearned({ content: args.content!, date: args.date }) };
198	      case "add-tomorrow": return { output: addTomorrow({ content: args.content!, date: args.date }) };
199	      case "add-session": return { output: addSession({ content: args.content!, date: args.date }) };
200	      case "add-note": return { output: addNote({ content: args.content!, date: args.date }) };
201	      case "add-log": return { output: addLog({ content: args.content!, date: args.date }) };
202	      case "edit": return { output: edit({ date: args.date, file: args.file, section: args.section || args.name, match: args.match, text: args.text! }) };
203	      default: return { output: `Unknown command: ${args.command}` };
204	    }
205	  },
