219	  append        --name <section> --content <text> [--date <date>]
220	  add-decision  --content <text> [--date <date>]
221	  add-learned   --content <text> [--date <date>]
222	  add-tomorrow  --content <text> [--date <date>]
223	  add-session   --content <text> [--date <date>]
224	  add-note      --content <text> [--date <date>]
225	  add-log       --content <text> [--date <date>]
