237	        result = appendSection({ name: flag(argv, "name") || "", content: flag(argv, "content") || "", date: flag(argv, "date") });
238	        break;
239	      case "add-decision":
240	        result = addDecision({ content: flag(argv, "content") || "", date: flag(argv, "date") });
241	        break;
242	      case "add-learned":
243	        result = addLearned({ content: flag(argv, "content") || "", date: flag(argv, "date") });
244	        break;
