#!/usr/bin/env bun
/**
 * sections.ts — Section-level read/append/edit for daily notes
 *
 * Avoids loading full notes into context — operates on specific sections only.
 *
 * CLI:
 *   bun src/tools/obsidian/sections.ts read --name <section> [--date <date>]
 *   bun src/tools/obsidian/sections.ts append --name <section> --content <text> [--date <date>]
 *   bun src/tools/obsidian/sections.ts add-decision --content <text> [--date <date>]
 *   bun src/tools/obsidian/sections.ts add-learned --content <text> [--date <date>]
 *   bun src/tools/obsidian/sections.ts add-tomorrow --content <text> [--date <date>]
 *   bun src/tools/obsidian/sections.ts add-session --content <text> [--date <date>]
 *   bun src/tools/obsidian/sections.ts add-note --content <text> [--date <date>]
 *   bun src/tools/obsidian/sections.ts add-log --content <text> [--date <date>]
 *   bun src/tools/obsidian/sections.ts edit --name <section> [--match <text>] --text <new> [--date <date>] [--file <path>]
 */

import { z } from "zod";
import type { ToolDefinition } from "../../registry/types.js";
import { parseDate } from "../../libs/dates.js";
import { readNote, writeNote, noteExists } from "../../libs/vault.js";
import {
  parse,
  serialize,
  findSection as omFindSection,
  appendToSection as omAppendToSection,
  replaceSectionContent as omReplaceSectionContent,
} from "../../libs/obsidian-md/index.js";
import { confirm, notFound, empty, timeNow } from "../../libs/format.js";
import { initializeDailyWithCarryForward, flag } from "./shared.js";

// ── Ensure daily note exists ────────────────────────────────────────────

function ensureDaily(date: string): string {
  const path = `daily/${date}.md`;
  if (!noteExists(path)) initializeDailyWithCarryForward(date);
  return path;
}

// ── Read a section ──────────────────────────────────────────────────────

export function readSection(args: { name: string; date?: string }): string {
  const date = parseDate(args.date);
  const path = `daily/${date}.md`;
  if (!noteExists(path)) return notFound("daily note", date);
  const content = readNote(path)!;
  const doc = parse(content);
  const section = omFindSection(doc, args.name);
  if (!section) return notFound(`section "## ${args.name}"`, date);

  // Return raw section body as string (same as old code)
  const lines = content.split(/\r?\n/);
  const sectionStartLine = section.line; // 1-based line of ## heading
  let sectionEnd = lines.length;
  for (let i = sectionStartLine; i < lines.length; i++) {
    if (lines[i].startsWith('## ')) { sectionEnd = i; break; }
  }
  const body = lines.slice(sectionStartLine, sectionEnd).join('\n').trim();
  if (!body) return empty(args.name, date);
  return body;
}

// ── Append to a section ─────────────────────────────────────────────────

export function appendSection(args: { name: string; content: string; date?: string; prefix?: string }): string {
  const date = parseDate(args.date);
  const path = ensureDaily(date);
  const note = readNote(path)!;
  const line = args.prefix ? `${args.prefix}${args.content}` : `- ${args.content}`;
  const doc = parse(note);
  const updated = omAppendToSection(doc, args.name, line);
  writeNote(path, serialize(updated));
  return confirm(`Added to ## ${args.name}`, date, args.content);
}

// ── Convenience appenders ───────────────────────────────────────────────

export function addDecision(args: { content: string; date?: string }): string {
  return appendSection({ name: "Decisions", content: args.content, date: args.date });
}

export function addLearned(args: { content: string; date?: string }): string {
  return appendSection({ name: "Learned", content: args.content, date: args.date });
}

export function addTomorrow(args: { content: string; date?: string }): string {
  return appendSection({ name: "Tomorrow", content: args.content, date: args.date, prefix: "- [ ] " });
}

export function addSession(args: { content: string; date?: string }): string {
  const date = parseDate(args.date);
  const path = ensureDaily(date);
  const note = readNote(path)!;
  const doc = parse(note);
  const updated = omAppendToSection(doc, "Session Work", `### ${args.content}`);
  writeNote(path, serialize(updated));
  return confirm("Session heading added", date, `### ${args.content}`);
}

export function addNote(args: { content: string; date?: string }): string {
  return appendSection({ name: "Notes", content: args.content, date: args.date });
}

export function addLog(args: { content: string; date?: string }): string {
  return appendSection({ name: "Log", content: `${timeNow()} — ${args.content}`, date: args.date });
}

// ── Edit section content ────────────────────────────────────────────────

export function edit(args: { date?: string; file?: string; section?: string; match?: string; text: string }): string {
  let path: string;
  if (args.file) {
    path = args.file.replace(/^vault\/notes\//, "");
    if (!path.endsWith(".md")) path += ".md";
  } else {
    const date = parseDate(args.date);
    path = `daily/${date}.md`;
  }

  if (!noteExists(path)) return notFound("note", path);
  const content = readNote(path)!;
  const doc = parse(content);

  if (args.section && args.match) {
    const sec = omFindSection(doc, args.section);
    if (!sec) return `No line matching "${args.match}" in ## ${args.section}.`;

    const matchLower = args.match.toLowerCase();
    for (const node of sec.body) {
      if (node.raw.toLowerCase().includes(matchLower)) {
        const matched = node.raw.trim();
        const prefix = node.raw.match(/^(\s*- (?:\[[ x]\] )?)/i);
        if (prefix) {
          node.raw = `${prefix[1]}${args.text}`;
        } else {
          node.raw = args.text;
        }
        node.dirty = true;
        writeNote(path, serialize(doc));
        return `Updated in ## ${args.section}: "${matched}" -> "${args.text}"`;
      }
    }
    return `No line matching "${args.match}" in ## ${args.section}.`;
  }

  if (args.section && !args.match) {
    const sec = omFindSection(doc, args.section);
    if (!sec) return notFound(`section "## ${args.section}"`, path);
    const updated = omReplaceSectionContent(doc, args.section, args.text);
    writeNote(path, serialize(updated));
    return `Replaced content of ## ${args.section} in ${path}`;
  }

  if (args.match) {
    const matchLower = args.match.toLowerCase();
    const lines = content.split(/\r?\n/);
    for (let i = 0; i < lines.length; i++) {
      if (lines[i].toLowerCase().includes(matchLower)) {
        const matched = lines[i].trim();
        lines[i] = args.text;
        writeNote(path, lines.join("\n"));
        return `Updated: "${matched}" -> "${args.text}"`;
      }
    }
    return `No line matching "${args.match}" in ${path}.`;
  }

  return `Specify section (with optional match), or match alone.`;
}

// ── Tool definition ─────────────────────────────────────────────────────

export const toolDef: ToolDefinition = {
  name: "obsidian_sections",
  description:
    "Section-level operations on daily notes. Commands: read (one section only), " +
    "append (generic), add-decision, add-learned, add-tomorrow, add-session, add-note, add-log, " +
    "edit (section content by match or replace).",
  inputSchema: z.object({
    command: z.enum(["read", "append", "add-decision", "add-learned", "add-tomorrow", "add-session", "add-note", "add-log", "edit"])
      .describe("Section command to run"),
    name: z.string().optional().describe("Section name (e.g., 'Decisions', 'Learned', 'Tomorrow')"),
    content: z.string().optional().describe("Content to add"),
    date: z.string().optional().describe("Target date (YYYY-MM-DD, 'tomorrow', 'yesterday')"),
    file: z.string().optional().describe("File path for edit (overrides date)"),
    section: z.string().optional().describe("Section name for edit"),
    match: z.string().optional().describe("Text to find for edit"),
    text: z.string().optional().describe("New text for edit"),
  }),
  tags: ["vault", "obsidian"],
  execute: async (args: any) => {
    switch (args.command) {
      case "read": return { output: readSection({ name: args.name!, date: args.date }) };
      case "append": return { output: appendSection({ name: args.name!, content: args.content!, date: args.date }) };
      case "add-decision": return { output: addDecision({ content: args.content!, date: args.date }) };
      case "add-learned": return { output: addLearned({ content: args.content!, date: args.date }) };
      case "add-tomorrow": return { output: addTomorrow({ content: args.content!, date: args.date }) };
      case "add-session": return { output: addSession({ content: args.content!, date: args.date }) };
      case "add-note": return { output: addNote({ content: args.content!, date: args.date }) };
      case "add-log": return { output: addLog({ content: args.content!, date: args.date }) };
      case "edit": return { output: edit({ date: args.date, file: args.file, section: args.section || args.name, match: args.match, text: args.text! }) };
      default: return { output: `Unknown command: ${args.command}` };
    }
  },
};

// ── CLI mode ────────────────────────────────────────────────────────────

if (import.meta.main) {
  const argv = process.argv.slice(2);
  const command = argv[0];

  if (!command || command === "--help") {
    console.log(`Usage: bun src/tools/obsidian/sections.ts <command> [flags]

Commands:
  read          --name <section> [--date <date>]
  append        --name <section> --content <text> [--date <date>]
  add-decision  --content <text> [--date <date>]
  add-learned   --content <text> [--date <date>]
  add-tomorrow  --content <text> [--date <date>]
  add-session   --content <text> [--date <date>]
  add-note      --content <text> [--date <date>]
  add-log       --content <text> [--date <date>]
  edit          --section <name> [--match <text>] --text <new> [--date <date>] [--file <path>]`);
    process.exit(0);
  }

  try {
    let result: string;
    switch (command) {
      case "read":
        result = readSection({ name: flag(argv, "name") || "", date: flag(argv, "date") });
        break;
      case "append":
        result = appendSection({ name: flag(argv, "name") || "", content: flag(argv, "content") || "", date: flag(argv, "date") });
        break;
      case "add-decision":
        result = addDecision({ content: flag(argv, "content") || "", date: flag(argv, "date") });
        break;
      case "add-learned":
        result = addLearned({ content: flag(argv, "content") || "", date: flag(argv, "date") });
        break;
      case "add-tomorrow":
        result = addTomorrow({ content: flag(argv, "content") || "", date: flag(argv, "date") });
        break;
      case "add-session":
        result = addSession({ content: flag(argv, "content") || "", date: flag(argv, "date") });
        break;
      case "add-note":
        result = addNote({ content: flag(argv, "content") || "", date: flag(argv, "date") });
        break;
      case "add-log":
        result = addLog({ content: flag(argv, "content") || "", date: flag(argv, "date") });
        break;
      case "edit":
        result = edit({
          date: flag(argv, "date"),
          file: flag(argv, "file"),
          section: flag(argv, "section"),
          match: flag(argv, "match"),
          text: flag(argv, "text") || "",
        });
        break;
      default:
        console.error(`Unknown command: ${command}. Run with --help for usage.`);
        process.exit(1);
    }
    console.log(result);
  } catch (err: any) {
    console.error(`Error: ${err.message}`);
    process.exit(1);
  }
}

