import type {
  Document, Section, Node, Task, TaskStatus, TaskFilter, MoveOpts, DocLink, Wikilink,
} from './types.js';
import { parse } from './parser.js';

// ── Helpers ───────────────────────────────────────────────────────────

function cloneTask(task: Task): Task {
  return {
    ...task,
    subtasks: task.subtasks.map(cloneTask),
    links: [...task.links],
    history: [...task.history],
  };
}

function cloneNode(node: Node): Node {
  if (node.type === 'task') return cloneTask(node as Task);
  return { ...node };
}

function cloneSection(section: Section): Section {
  return {
    ...section,
    body: section.body.map(cloneNode),
  };
}

function cloneDoc(doc: Document): Document {
  return {
    ...doc,
    frontmatter: { ...doc.frontmatter },
    preamble: doc.preamble.map(cloneNode),
    sections: doc.sections.map(cloneSection),
  };
}

function tasksFromNodes(nodes: Node[]): Task[] {
  const result: Task[] = [];
  for (const node of nodes) {
    if (node.type === 'task') {
      const task = node as Task;
      result.push(task);
      result.push(...task.subtasks);
    }
  }
  return result;
}

function allTasks(doc: Document): Task[] {
  const result: Task[] = [];
  for (const node of doc.preamble) {
    if (node.type === 'task') {
      result.push(node as Task);
      result.push(...(node as Task).subtasks);
    }
  }
  for (const section of doc.sections) {
    result.push(...tasksFromNodes(section.body));
  }
  return result;
}

// ── Section operations ────────────────────────────────────────────────

export function findSection(doc: Document, name: string): Section | undefined {
  const lower = name.toLowerCase();
  return doc.sections.find(s => s.heading.toLowerCase() === lower);
}

export function appendToSection(doc: Document, name: string, content: string): Document {
  const result = cloneDoc(doc);
  let section = result.sections.find(s => s.heading.toLowerCase() === name.toLowerCase());

  if (!section) {
    // Create section at end
    const level = 2;
    const raw = `${'#'.repeat(level)} ${name}`;
    section = {
      heading: name,
      level,
      body: [],
      line: 0,
      raw,
    };
    result.sections.push(section);
  }

  // Parse new content
  const newNodes = parseNodes(content);

  // Insert before trailing blank nodes
  let insertIdx = section.body.length;
  while (insertIdx > 0 && section.body[insertIdx - 1].type === 'blank') {
    insertIdx--;
  }

  section.body.splice(insertIdx, 0, ...newNodes);
  return result;
}

export function replaceSectionContent(doc: Document, name: string, content: string): Document {
  const result = cloneDoc(doc);
  let section = result.sections.find(s => s.heading.toLowerCase() === name.toLowerCase());

  if (!section) {
    const level = 2;
    const raw = `${'#'.repeat(level)} ${name}`;
    section = {
      heading: name,
      level,
      body: [],
      line: 0,
      raw,
    };
    result.sections.push(section);
  }

  section.body = parseNodes(content);
  return result;
}

// Parse a content string into nodes (no frontmatter, no sections)
function parseNodes(content: string): Node[] {
  // Wrap in a minimal doc to reuse parse()
  const doc = parse(content);
  // Content without ## headings goes to preamble
  const nodes: Node[] = [...doc.preamble];
  for (const sec of doc.sections) {
    // Include section heading as heading node + body
    nodes.push({
      type: 'heading',
      line: sec.line,
      raw: sec.raw,
      dirty: true,
      level: sec.level,
      content: sec.heading,
    });
    nodes.push(...sec.body);
  }
  // Mark all dirty since they're new
  for (const n of nodes) {
    n.dirty = true;
    if (n.type === 'task') {
      for (const sub of (n as Task).subtasks) sub.dirty = true;
    }
  }
  return nodes;
}

// ── Task operations ───────────────────────────────────────────────────

export function findTask(doc: Document, id: string): Task | undefined {
  return allTasks(doc).find(t => t.id === id);
}

export function listTasks(doc: Document, filter?: TaskFilter): Task[] {
  const tasks = allTasks(doc);
  if (!filter) return tasks;

  return tasks.filter(task => {
    if (filter.status !== undefined) {
      const statuses = Array.isArray(filter.status) ? filter.status : [filter.status];
      if (!statuses.includes(task.status)) return false;
    }
    if (filter.search !== undefined) {
      if (!task.content.toLowerCase().includes(filter.search.toLowerCase())) return false;
    }
    if (filter.hasDocLinks !== undefined) {
      if (filter.hasDocLinks && task.links.length === 0) return false;
      if (!filter.hasDocLinks && task.links.length > 0) return false;
    }
    if (filter.hasHistory !== undefined) {
      if (filter.hasHistory && task.history.length === 0) return false;
      if (!filter.hasHistory && task.history.length > 0) return false;
    }
    return true;
  });
}

export function getNextTaskId(doc: Document, parentId?: string): string {
  if (parentId) {
    const parent = findTask(doc, parentId);
    if (!parent) return `${parentId}.1`;
    const maxSub = parent.subtasks
      .map(t => {
        const parts = t.id.split('.');
        return parseInt(parts[parts.length - 1], 10) || 0;
      })
      .reduce((a, b) => Math.max(a, b), 0);
    return `${parentId}.${maxSub + 1}`;
  }

  // Find max top-level integer ID across all sections
  let max = 0;
  for (const section of doc.sections) {
    for (const node of section.body) {
      if (node.type === 'task') {
        const task = node as Task;
        const num = parseInt(task.id, 10);
        if (!isNaN(num) && num > max) max = num;
      }
    }
  }
  return String(max + 1);
}

export function addTask(doc: Document, content: string, parent?: string): Document {
  const result = cloneDoc(doc);

  if (parent) {
    const parentTask = findTask(result, parent);
    if (!parentTask) throw new Error(`Parent task ${parent} not found`);
    const subId = getNextTaskId(result, parent);
    const newTask: Task = {
      type: 'task',
      line: 0,
      raw: '',
      dirty: true,
      id: subId,
      status: 'todo',
      content,
      subtasks: [],
      indent: parentTask.indent + 2,
      links: [],
      history: [],
      isLabel: false,
      isStrikethrough: false,
    };
    parentTask.subtasks.push(newTask);
    return result;
  }

  // Add to Tasks section
  let taskSection = result.sections.find(s => s.heading.toLowerCase() === 'tasks');
  if (!taskSection) {
    taskSection = {
      heading: 'Tasks',
      level: 2,
      body: [],
      line: 0,
      raw: '## Tasks',
    };
    result.sections.push(taskSection);
  }

  const newId = getNextTaskId(result);
  const newTask: Task = {
    type: 'task',
    line: 0,
    raw: '',
    dirty: true,
    id: newId,
    status: 'todo',
    content,
    subtasks: [],
    indent: 0,
    links: [],
    history: [],
    isLabel: false,
    isStrikethrough: false,
  };

  // Insert before trailing blank nodes
  let insertIdx = taskSection.body.length;
  while (insertIdx > 0 && taskSection.body[insertIdx - 1].type === 'blank') {
    insertIdx--;
  }
  taskSection.body.splice(insertIdx, 0, newTask);
  return result;
}

export function setTaskStatus(doc: Document, id: string, status: TaskStatus): Document {
  const result = cloneDoc(doc);
  const task = findTask(result, id);
  if (!task) throw new Error(`Task ${id} not found`);
  task.status = status;
  task.dirty = true;
  return result;
}

export function completeTask(doc: Document, id: string): Document {
  const result = cloneDoc(doc);
  const task = findTask(result, id);
  if (!task) throw new Error(`Task ${id} not found`);
  task.status = 'done';
  task.completion = new Date().toISOString().slice(0, 10);
  task.dirty = true;
  return result;
}

export function moveTask(doc: Document, id: string, opts: MoveOpts): Document {
  const result = cloneDoc(doc);

  // Find the task and its container
  function findTaskInNodes(nodes: Node[], targetId: string): { task: Task; nodes: Node[]; index: number } | null {
    for (let i = 0; i < nodes.length; i++) {
      const node = nodes[i];
      if (node.type === 'task') {
        const t = node as Task;
        if (t.id === targetId) return { task: t, nodes, index: i };
        // Search subtasks
        for (let j = 0; j < t.subtasks.length; j++) {
          if (t.subtasks[j].id === targetId) {
            return { task: t.subtasks[j], nodes: t.subtasks, index: j };
          }
        }
      }
    }
    return null;
  }

  function findInDoc(targetId: string): { task: Task; nodes: Node[] | Task[]; index: number } | null {
    let found = findTaskInNodes(result.preamble, targetId);
    if (found) return found;
    for (const sec of result.sections) {
      found = findTaskInNodes(sec.body, targetId);
      if (found) return found;
    }
    return null;
  }

  if (opts.under) {
    const found = findInDoc(id);
    if (!found) throw new Error(`Task ${id} not found`);
    const { task, nodes, index } = found;

    // Remove from current position
    (nodes as any[]).splice(index, 1);

    // Find parent
    const parentFound = findInDoc(opts.under);
    if (!parentFound) throw new Error(`Parent task ${opts.under} not found`);
    const parentTask = parentFound.task;

    // Reassign ID
    const newSubId = getNextTaskId(result, opts.under);
    task.id = newSubId;
    task.indent = parentTask.indent + 2;
    task.dirty = true;
    parentTask.subtasks.push(task);
  } else if (opts.toTop) {
    const found = findInDoc(id);
    if (!found) throw new Error(`Task ${id} not found`);
    const { task, nodes, index } = found;

    // Remove from current position
    (nodes as any[]).splice(index, 1);

    // Get Tasks section
    let taskSection = result.sections.find(s => s.heading.toLowerCase() === 'tasks');
    if (!taskSection) {
      taskSection = {
        heading: 'Tasks', level: 2, body: [], line: 0, raw: '## Tasks',
      };
      result.sections.push(taskSection);
    }

    // Assign next top-level ID
    task.id = getNextTaskId(result);
    task.indent = 0;
    task.dirty = true;

    let insertIdx = taskSection.body.length;
    while (insertIdx > 0 && taskSection.body[insertIdx - 1].type === 'blank') insertIdx--;
    taskSection.body.splice(insertIdx, 0, task);
  } else if (opts.before || opts.after) {
    const refId = opts.before ?? opts.after!;
    const found = findInDoc(id);
    const refFound = findInDoc(refId);
    if (!found) throw new Error(`Task ${id} not found`);
    if (!refFound) throw new Error(`Reference task ${refId} not found`);

    const { task, nodes: srcNodes, index: srcIndex } = found;
    (srcNodes as any[]).splice(srcIndex, 1);

    // Re-find ref after splice (indices may have shifted)
    const refFoundAgain = findInDoc(refId);
    if (!refFoundAgain) throw new Error(`Reference task ${refId} not found after splice`);
    const { nodes: dstNodes, index: dstIndex } = refFoundAgain;

    const insertAt = opts.before ? dstIndex : dstIndex + 1;
    task.dirty = true;
    (dstNodes as any[]).splice(insertAt, 0, task);
  }

  return result;
}

export function linkDoc(doc: Document, taskId: string, docPath: string): Document {
  const result = cloneDoc(doc);
  const task = findTask(result, taskId);
  if (!task) throw new Error(`Task ${taskId} not found`);
  const nextNum = task.links.length > 0 ? Math.max(...task.links.map(l => l.number)) + 1 : 1;
  task.links.push({ path: docPath, number: nextNum });
  task.dirty = true;
  return result;
}

export function unlinkDoc(doc: Document, taskId: string, docPath: string): Document {
  const result = cloneDoc(doc);
  const task = findTask(result, taskId);
  if (!task) throw new Error(`Task ${taskId} not found`);
  task.links = task.links.filter(l => l.path !== docPath);
  // Renumber remaining
  task.links.forEach((l, i) => (l.number = i + 1));
  task.dirty = true;
  return result;
}

// ── Carry-forward ─────────────────────────────────────────────────────

function dateToAlias(date: string): string {
  // "2026-04-01" → "04-01"
  return date.slice(5);
}

export function carryForward(
  source: Document,
  target: Document,
  targetDate: string,
): { source: Document; target: Document } {
  const srcResult = cloneDoc(source);
  const tgtResult = cloneDoc(target);

  // Infer source date from frontmatter or raw
  const sourceDate: string = (srcResult.frontmatter.title as string) ?? '';
  const targetAlias = dateToAlias(targetDate);
  const sourceAlias = dateToAlias(sourceDate);

  const incompleteSections = srcResult.sections.filter(
    s => s.heading.toLowerCase() === 'tasks',
  );

  const incompleteStatuses: TaskStatus[] = ['todo', 'in_progress', 'urgent', 'question'];

  function shouldCarry(task: Task): boolean {
    return incompleteStatuses.includes(task.status);
  }

  // Get or create Tasks section in target
  let targetTasksSection = tgtResult.sections.find(
    s => s.heading.toLowerCase() === 'tasks',
  );
  if (!targetTasksSection) {
    targetTasksSection = {
      heading: 'Tasks',
      level: 2,
      body: [],
      line: 0,
      raw: '## Tasks',
    };
    tgtResult.sections.push(targetTasksSection);
  }

  for (const section of incompleteSections) {
    for (const node of section.body) {
      if (node.type !== 'task') continue;
      const task = node as Task;

      if (!shouldCarry(task)) continue;

      // Skip labels where all subtasks are already complete
      if (task.isLabel && task.subtasks.every(s => !shouldCarry(s))) continue;

      // Capture original status before mutating source
      const originalStatus = task.status;

      // Mark source task as deferred
      task.status = 'deferred';
      task.isStrikethrough = true;
      task.forward = { path: `notes/daily/${targetDate}`, alias: targetAlias };
      task.dirty = true;

      // Build new task for target
      const newId = getNextTaskId(tgtResult);

      // Carry history: append source date
      const newHistory: Wikilink[] = [
        ...task.history,
        { path: `notes/daily/${sourceDate}`, alias: sourceAlias },
      ];

      const newTask: Task = {
        type: 'task',
        line: 0,
        raw: '',
        dirty: true,
        id: newId,
        status: originalStatus,
        content: task.content,
        subtasks: [],
        indent: 0,
        links: [...task.links],
        history: newHistory,
        isLabel: task.isLabel,
        isStrikethrough: false,
      };

      // Carry subtasks
      let subCounter = 1;
      for (const sub of task.subtasks) {
        if (shouldCarry(sub)) {
          const subOriginalStatus = sub.status;
          const subHistory: Wikilink[] = [
            ...sub.history,
            { path: `notes/daily/${sourceDate}`, alias: sourceAlias },
          ];
          const newSub: Task = {
            type: 'task',
            line: 0,
            raw: '',
            dirty: true,
            id: `${newId}.${subCounter++}`,
            status: subOriginalStatus,
            content: sub.content,
            subtasks: [],
            indent: 2,
            links: [...sub.links],
            history: subHistory,
            isLabel: sub.isLabel,
            isStrikethrough: false,
          };
          newTask.subtasks.push(newSub);
        }
      }

      // Also mark source subtasks as deferred
      for (const sub of task.subtasks) {
        if (shouldCarry(sub)) {
          sub.status = 'deferred';
          sub.isStrikethrough = true;
          sub.forward = { path: `notes/daily/${targetDate}`, alias: targetAlias };
          sub.dirty = true;
        }
      }

      // Insert in target before trailing blanks
      let insertIdx = targetTasksSection.body.length;
      while (insertIdx > 0 && targetTasksSection.body[insertIdx - 1].type === 'blank') {
        insertIdx--;
      }
      targetTasksSection.body.splice(insertIdx, 0, newTask);
    }
  }

  return { source: srcResult, target: tgtResult };
}

export * from './types.js';
export { parse } from './parser.js';
export { serialize } from './serializer.js';
export {
  findSection,
  appendToSection,
  replaceSectionContent,
  findTask,
  listTasks,
  addTask,
  setTaskStatus,
  completeTask,
  moveTask,
  linkDoc,
  unlinkDoc,
  getNextTaskId,
  carryForward,
} from './operations.js';

