/**
 * shared.ts — Shared helpers, constants, and types for obsidian tools
 */

import { listNotes, readNote, writeNote, noteExists } from "../../libs/vault.js";
import { serializeFrontmatter, updateFrontmatter } from "../../libs/frontmatter.js";
import {
  parse,
  serialize,
  appendToSection as omAppendToSection,
  addTask as omAddTask,
  getNextTaskId,
  carryForward as omCarryForward,
  findSection as omFindSection,
} from "../../libs/obsidian-md/index.js";
import type { Task, TableNode } from "../../libs/obsidian-md/types.js";

// ── Constants ───────────────────────────────────────────────────────────

export const SECTION_NAMES = [
  "Tasks",
  "Log",
  "Session Work",
  "Decisions",
  "Learned",
  "Meetings",
  "Tomorrow",
  "Notes",
] as const;

export type SectionName = (typeof SECTION_NAMES)[number];

// ── Daily template ──────────────────────────────────────────────────────

export function createDailyTemplate(date: string): string {
  const id = `daily-${date.replace(/-/g, "")}`;
  const fm = serializeFrontmatter({ id, title: date, tags: ["daily"], connected: [] });
  const summary = [
    "## Summary",
    "",
    "| Metric | Count |",
    "|--------|-------|",
    '| Tasks completed | `$= const t = dv.current().file.tasks.where(t => t.section.subpath === "Tasks"); dv.span(t.where(t => t.completed).length + "/" + t.length)` |',
    '| Sessions | `$= const tops = ["Summary","Tasks","Log","Session Work","Decisions","Learned","Meetings","Tomorrow","Notes"]; dv.span(new Set(dv.current().file.lists.where(l => !tops.includes(l.section.subpath) && !l.task).map(l => l.section.subpath).values).size)` |',
    '| Decisions made | `$= dv.span(dv.current().file.lists.where(l => l.section.subpath === "Decisions" && !l.task).length)` |',
    '| Things learned | `$= dv.span(dv.current().file.lists.where(l => l.section.subpath === "Learned" && !l.task).length)` |',
    '| Items for tomorrow | `$= dv.span(dv.current().file.tasks.where(t => t.section.subpath === "Tomorrow").length)` |',
    '| Meetings | `$= dv.span(dv.current().file.lists.where(l => l.section.subpath === "Meetings" && l.text.includes("[[")).length)` |',
    '| Connected notes | `$= const c = dv.current().connected; dv.span(c ? c.length : 0)` |',
    "",
    "**Focus areas:** (pending)",
  ].join("\n");
  return `${fm}\n\n${summary}\n\n## Tasks\n\n## Log\n\n## Session Work\n\n## Decisions\n\n## Learned\n\n## Meetings\n\n## Tomorrow\n`;
}

// ── Carry-forward ───────────────────────────────────────────────────────

export function getPreviousDate(date: string): string | null {
  const files = listNotes("daily");
  const sorted = files.map((f) => f.replace(".md", "")).filter((d) => d < date).sort().reverse();
  return sorted.length > 0 ? sorted[0] : null;
}

export function carryForwardTasks(targetDate: string): { carried: string[]; previousDate: string | null } {
  const prevDate = getPreviousDate(targetDate);
  if (!prevDate) return { carried: [], previousDate: null };

  const prevPath = `daily/${prevDate}.md`;
  const prevContent = readNote(prevPath);
  if (!prevContent) return { carried: [], previousDate: prevDate };

  const targetPath = `daily/${targetDate}.md`;
  const targetContent = readNote(targetPath) || createDailyTemplate(targetDate);

  const sourceDoc = parse(prevContent);
  const targetDoc = parse(targetContent);

  const { source: updatedSource, target: updatedTarget } = omCarryForward(sourceDoc, targetDoc, targetDate);

  // Update previous note
  const updatedPrevContent = updateFrontmatter(
    serialize(updatedSource),
    { connected: [`[[notes/daily/${targetDate}]]`] },
  );
  writeNote(prevPath, updatedPrevContent);

  // Write target so subsequent reads are up-to-date
  writeNote(targetPath, serialize(updatedTarget));

  // Build "carried" list for reporting (same format as old code)
  const tasksSection = omFindSection(updatedTarget, 'Tasks');
  const carried: string[] = [];
  if (tasksSection) {
    for (const node of tasksSection.body) {
      if (node.type === 'task') {
        const t = node as Task;
        if (t.history.length > 0) {
          // This is a carried task
          carried.push(`- [ ] ${t.content} ← [[notes/daily/${prevDate}|${prevDate.slice(5)}]]`);
          for (const sub of t.subtasks) {
            carried.push(`  - [ ] ${sub.content} ← [[notes/daily/${prevDate}|${prevDate.slice(5)}]]`);
          }
        }
      }
    }
  }

  return { carried, previousDate: prevDate };
}

export function initializeDailyWithCarryForward(date: string): string {
  let note = createDailyTemplate(date);
  writeNote(`daily/${date}.md`, note);

  const prevDate = getPreviousDate(date);
  if (!prevDate) {
    return `Created daily note for ${date} (no tasks to carry forward)`;
  }

  const prevPath = `daily/${prevDate}.md`;
  const prevContent = readNote(prevPath);
  if (!prevContent) {
    return `Created daily note for ${date} (no tasks to carry forward)`;
  }

  note = readNote(`daily/${date}.md`)!;
  const sourceDoc = parse(prevContent);
  const targetDoc = parse(note);

  const { source: updatedSource, target: updatedTarget } = omCarryForward(sourceDoc, targetDoc, date);

  // Check if anything was carried
  const tasksSection = omFindSection(updatedTarget, 'Tasks');
  const carriedCount = tasksSection
