#!/usr/bin/env bun
/**
 * tasks.ts — Task CRUD: add, complete, set status, move, link, unlink, list, summary
 *
 * CLI:
 *   bun src/tools/obsidian/tasks.ts add --content <text> [--parent <num>] [--date <date>]
 *   bun src/tools/obsidian/tasks.ts complete --task <num|text> [--date <date>]
 *   bun src/tools/obsidian/tasks.ts status --task <num|text> --status <status> [--date <date>]
 *   bun src/tools/obsidian/tasks.ts move --task <num|text> [--to-date <date>] [--under <num>] [--to-top] [--date <date>]
 *   bun src/tools/obsidian/tasks.ts link --task <num|text> --doc <path> [--date <date>]
 *   bun src/tools/obsidian/tasks.ts unlink --task <num|text> --doc <path> [--date <date>]
 *   bun src/tools/obsidian/tasks.ts list [--date <date>]
 *   bun src/tools/obsidian/tasks.ts summary [--date <date>]
 */

