        break;
      case "add-learned":
        result = addLearned({ content: flag(argv, "content") || "", date: flag(argv, "date") });
        break;
      case "add-tomorrow":
        result = addTomorrow({ content: flag(argv, "content") || "", date: flag(argv, "date") });
        break;
      case "add-session":
        result = addSession({ content: flag(argv, "content") || "", date: flag(argv, "date") });
        break;
      case "add-note":
        result = addNote({ content: flag(argv, "content") || "", date: flag(argv, "date") });
        break;
      case "add-log":
        result = addLog({ content: flag(argv, "content") || "", date: flag(argv, "date") });
