          file: flag(argv, "file"),
          section: flag(argv, "section"),
          match: flag(argv, "match"),
          text: flag(argv, "text") || "",
        });
        break;
      default:
        console.error(`Unknown command: ${command}. Run with --help for usage.`);
        process.exit(1);
    }
    console.log(result);
  } catch (err: any) {
    console.error(`Error: ${err.message}`);
    process.exit(1);
  }
}

