1	#!/usr/bin/env bun
2	/**
3	 * morning.ts — Session briefing for Freddie (/morning)
4	 *
5	 * Displays: greeting → tasks (open + in-progress) → last session → suggestions → knowledge summary.
6	 * Tasks come from tasks.ts CLI for consistent formatting.
7	 *
8	 * Design: fast (<500ms target), read-only, no file mutations.
9	 */
10	
11	import { readFileSync, readdirSync, existsSync } from "fs";
12	import { join, basename } from "path";
13	import { execSync } from "child_process";
14	import { fromRoot } from "../libs/paths.js";
15	import { today, now } from "../libs/dates.js";
16	
17	// ── Paths ─────────────────────────────────────────────────────────────────
18	// Souls + Freddie knowledge already loaded by startup.ts hook
19	
20	const MEMORY_DIR = fromRoot("vault", "studio", "memory");
21	
22	// ── Greetings ─────────────────────────────────────────────────────────────
23	
24	const GREETINGS = {
25	  morning: [
26	    "Good morning, sir! The studio is warmed up and ready.",
27	    "Morning, sir. Fresh day, fresh context. Shall we begin?",
28	    "Good morning. I've laid out the briefing — coffee's on you.",
29	    "Rise and shine, sir. The agents are standing by.",
30	  ],
31	  afternoon: [
32	    "Good afternoon, sir. What are we building today?",
33	    "Afternoon, sir. The board is set. Your move.",
34	    "Good afternoon. I've reviewed the state of things — here's where we are.",
35	    "Afternoon, sir. Let's pick up where we left off.",
36	  ],
37	  evening: [
38	    "Good evening, sir. Ready for your shift?",
39	    "Evening, sir. The night shift has its advantages — fewer interruptions.",
40	    "Good evening. I've prepared your briefing. The vault is quiet.",
41	    "Evening, sir. Let's make the most of the quiet hours.",
42	  ],
43	};
44	
45	function getGreeting(hour: number): string {
46	  let pool: string[];
47	  if (hour >= 5 && hour < 12) pool = GREETINGS.morning;
48	  else if (hour >= 12 && hour < 18) pool = GREETINGS.afternoon;
49	  else pool = GREETINGS.evening;
50	  return pool[Math.floor(Math.random() * pool.length)];
51	}
52	
53	// ── Knowledge scanner ─────────────────────────────────────────────────────
54	
55	interface AgentMemoryStatus {
56	  agent: string;
57	  inboxCount: number;
58	  knowledgeCount: number;
59	}
60	
61	function scanAgentMemory(): AgentMemoryStatus[] {
62	  if (!existsSync(MEMORY_DIR)) return [];
63	  const agents = readdirSync(MEMORY_DIR, { withFileTypes: true })
64	    .filter((d) => d.isDirectory())
65	    .map((d) => d.name);
66	
67	  return agents
68	    .map((agent) => {
69	      const inboxDir = join(MEMORY_DIR, agent, "inbox");
70	      const knowledgeDir = join(MEMORY_DIR, agent, "knowledge");
71	      const inboxCount = existsSync(inboxDir)
72	        ? readdirSync(inboxDir).filter((f) => f.endsWith(".md")).length
73	        : 0;
74	      const knowledgeCount = existsSync(knowledgeDir)
75	        ? readdirSync(knowledgeDir).filter((f) => f.endsWith(".md")).length
76	        : 0;
77	      return { agent, inboxCount, knowledgeCount };
78	    })
79	    .filter((a) => a.inboxCount > 0 || a.knowledgeCount > 0);
80	}
81	
82	// ── Task loader via tasks.ts CLI ──────────────────────────────────────────
83	
84	interface TaskDisplay {
85	  lines: string[];
86	  openCount: number;
87	  inProgressCount: number;
88	  doneCount: number;
89	}
90	
91	function loadTasks(date: string): TaskDisplay {
92	  const tasksScript = fromRoot("src", "tools", "obsidian", "tasks.ts");
93	  const result: TaskDisplay = { lines: [], openCount: 0, inProgressCount: 0, doneCount: 0 };
94	
95	  try {
96	    // Get summary for counts
97	    const summaryOutput = execSync(`bun "${tasksScript}" summary --date ${date}`, {
98	      encoding: "utf-8",
99	      timeout: 5000,
100	    }).trim();
101	
102	    // Parse counts from summary line: "2026-03-31: 12/24 tasks — 12 [x] done, 10 [>] deferred, ..."
103	    const doneMatch = summaryOutput.match(/(\d+) \[x\] done/);
104	    if (doneMatch) result.doneCount = parseInt(doneMatch[1], 10);
105	
106	    // Get todo tasks ([ ] only — excludes in-progress, urgent, question)
107	    const openOutput = execSync(`bun "${tasksScript}" list --date ${date} --filter todo`, {
108	      encoding: "utf-8",
109	      timeout: 5000,
110	    }).trim();
111	
112	    // Get in-progress tasks ([/] only)
113	    const inProgressOutput = execSync(`bun "${tasksScript}" list --date ${date} --filter in_progress`, {
114	      encoding: "utf-8",
115	      timeout: 5000,
116	    }).trim();
117	
118	    // Parse task lines (skip the summary header line)
119	    const parseTaskLines = (output: string, status: "open" | "in_progress"): string[] => {
120	      const lines = output.split("\n");
121	      const taskLines: string[] = [];
122	      for (const line of lines) {
123	        // Skip header/summary lines
124	        if (line.startsWith("No tasks") || line.match(/^\d{4}-\d{2}-\d{2}:/)) continue;
125	        if (!line.trim()) continue;
126	
127	        // Match task lines: [ ] [1] or [/] [2] or indented subtasks
128	        const topTask = line.match(/^\[[ /x>~-]\]\s+\[(\d+)\]\s+(.+)/);
129	        const subTask = line.match(/^\s+\[[ /x>~-]\]\s+\[(\d+\.\d+)\]\s+(.+)/);
130	
131	        if (topTask) {
132	          const marker = status === "in_progress" ? "[/]" : "[ ]";
133	          taskLines.push(`${marker} [${topTask[1]}] - ${topTask[2]}`);
134	        } else if (subTask) {
135	          const marker = status === "in_progress" ? "[/]" : "[ ]";
136	          taskLines.push(`    ${marker} [${subTask[1]}] ${subTask[2]}`);
137	        }
138	      }
139	      return taskLines;
140	    };
141	
142	    const openLines = parseTaskLines(openOutput, "open");
143	    const ipLines = parseTaskLines(inProgressOutput, "in_progress");
144	
145	    result.openCount = openLines.filter((l) => !l.startsWith("    ")).length;
146	    result.inProgressCount = ipLines.filter((l) => !l.startsWith("    ")).length;
147	    result.lines = [...openLines, ...ipLines];
148	  } catch {
149	    // tasks.ts failed — non-blocking
150	  }
151	
152	  return result;
153	}
154	
155	// ── Suggestions ───────────────────────────────────────────────────────────
156	
157	function buildSuggestions(
158	  agentStatuses: AgentMemoryStatus[],
159	  taskDisplay: TaskDisplay
160	): string[] {
161	  const suggestions: string[] = [];
162	
163	  const needsConsolidation = agentStatuses.filter((a) => a.inboxCount >= 3);
164	  for (const a of needsConsolidation) {
165	    suggestions.push(
166	      `${capitalize(a.agent)} has ${a.inboxCount} inbox items — consolidation ready`
167	    );
168	  }
169	
170	  const hasInbox = agentStatuses.filter((a) => a.inboxCount > 0 && a.inboxCount < 3);
171	  if (hasInbox.length > 0) {
172	    const names = hasInbox
173	      .map((a) => `${capitalize(a.agent)} (${a.inboxCount})`)
174	      .join(", ");
175	    suggestions.push(`Inbox items: ${names}`);
176	  }
177	
178	  if (taskDisplay.openCount > 5) {
179	    suggestions.push(
180	      `${taskDisplay.openCount} open tasks — consider triaging or deferring some`
181	    );
182	  }
183	
184	  return suggestions;
185	}
186	
187	function capitalize(s: string): string {
188	  return s.charAt(0).toUpperCase() + s.slice(1);
189	}
190	
191	// ── Main ──────────────────────────────────────────────────────────────────
192	
193	function main() {
194	  const { date, time } = now();
195	  const hour = parseInt(time.slice(0, 2), 10);
196	  const greeting = getGreeting(hour);
197	  const agentStatuses = scanAgentMemory();
198	  const taskDisplay = loadTasks(date);
199	  const suggestions = buildSuggestions(agentStatuses, taskDisplay);
200	
201	  const lines: string[] = [];
202	
203	  lines.push(greeting);
204	  lines.push("");
205	
206	  // Tasks
207	  lines.push("━━ Briefing ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
208	  lines.push("");
209	
210	  if (taskDisplay.lines.length > 0) {
211	    lines.push("Tasks:");
212	    for (const line of taskDisplay.lines) {
213	      lines.push(`  ${line}`);
214	    }
215	    lines.push("");
216	    lines.push(
217	      `  Summary: ${taskDisplay.openCount} Open | ${taskDisplay.inProgressCount} In-Progress | ${taskDisplay.doneCount} Done`
218	    );
219	    lines.push("");
220	  } else {
221	    lines.push("Tasks: No open or in-progress tasks.");
222	    lines.push("");
223	  }
224	
225	  // Suggestions
226	  if (suggestions.length > 0) {
227	    lines.push("Suggested:");
228	    for (const s of suggestions) {
229	      lines.push(`  > ${s}`);
230	    }
231	    lines.push("");
232	  }
233	
234	  lines.push("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
235	
236	  process.stdout.write(lines.join("\n"));
237	}
238	
239	try {
240	  main();
241	} catch (err) {
242	  process.stderr.write(
243	    `[init] Error: ${err instanceof Error ? err.message : String(err)}\n`
244	  );
245	}
246	
247	process.exit(0);
248

