  ],
  afternoon: [
    "Good afternoon, sir. What are we building today?",
    "Afternoon, sir. The board is set. Your move.",
    "Good afternoon. I've reviewed the state of things — here's where we are.",
    "Afternoon, sir. Let's pick up where we left off.",
  ],
  evening: [
    "Good evening, sir. Ready for your shift?",
    "Evening, sir. The night shift has its advantages — fewer interruptions.",
    "Good evening. I've prepared your briefing. The vault is quiet.",
    "Evening, sir. Let's make the most of the quiet hours.",
  ],
};

function getGreeting(hour: number): string {
  let pool: string[];
  if (hour >= 5 && hour < 12) pool = GREETINGS.morning;
  else if (hour >= 12 && hour < 18) pool = GREETINGS.afternoon;
  else pool = GREETINGS.evening;
  return pool[Math.floor(Math.random() * pool.length)];
}

// ── Inbox scanner ─────────────────────────────────────────────────────────

interface AgentMemoryStatus {
  agent: string;
  inboxCount: number;
}

function scanInbox(): AgentMemoryStatus[] {
  if (!existsSync(MEMORY_DIR)) return [];
  const agents = readdirSync(MEMORY_DIR, { withFileTypes: true })
    .filter((d) => d.isDirectory())
    .map((d) => d.name);

  return agents
    .map((agent) => {
      const inboxDir = join(MEMORY_DIR, agent, "inbox");
      const inboxCount = existsSync(inboxDir)
        ? readdirSync(inboxDir).filter((f) => f.endsWith(".md")).length
        : 0;
      return { agent, inboxCount };
    })
    .filter((a) => a.inboxCount > 0);
}

// ── Short title ──────────────────────────────────────────────────────────

function shortTitle(text: string, max = 60): string {
  // Cut at first — (em dash) or . after the initial phrase, if within limit
  const emDash = text.indexOf(' — ');
  if (emDash > 0 && emDash <= max) return text.slice(0, emDash);
  const dot = text.indexOf('. ');
  if (dot > 0 && dot <= max) return text.slice(0, dot);
  if (text.length <= max) return text;
  // Hard truncate at last word boundary before max
  const truncated = text.slice(0, max);
  const lastSpace = truncated.lastIndexOf(' ');
  return (lastSpace > max * 0.6 ? truncated.slice(0, lastSpace) : truncated) + '…';
}

// ── Task loader (direct import, no subprocess) ───────────────────────────

interface TaskDisplay {
  lines: string[];
  openCount: number;
  inProgressCount: number;
  doneCount: number;
}

function loadTasks(date: string): TaskDisplay {
  const result: TaskDisplay = { lines: [], openCount: 0, inProgressCount: 0, doneCount: 0 };
  const path = `daily/${date}.md`;
  if (!noteExists(path)) return result;

  const content = readNote(path);
  if (!content) return result;

  const doc = parse(content);
  const tasksSection = findSection(doc, 'Tasks');
  if (!tasksSection) return result;

  const c = countItems(content);
  result.doneCount = c.done;

  // Collect tasks from AST
  for (const node of tasksSection.body) {
    if (node.type !== 'task') continue;
    const task = node as Task;
    if (task.isLabel) continue;

    const isOpen = task.status === 'todo' || task.status === 'in_progress' || task.status === 'urgent' || task.status === 'question';
    if (!isOpen) continue;

    const marker = task.status === 'in_progress' ? '[/]' : '[ ]';
    const age = task.history.length > 0 ? ` (${task.history.length} days)` : '';
    const docs = task.links.length > 0 ? ` (docs: ${task.links.length})` : '';
    result.lines.push(`${marker} [${task.id}] - ${task.content}${docs}${age}`);

    if (task.status === 'in_progress') result.inProgressCount++;
    else result.openCount++;

    for (const sub of task.subtasks) {
      const subIsOpen = sub.status === 'todo' || sub.status === 'in_progress';
      if (!subIsOpen) continue;
      const subMarker = sub.status === 'in_progress' ? '[/]' : '[ ]';
      result.lines.push(`    ${subMarker} [${sub.id}] ${sub.content}${sub.history.length > 0 ? ` (${sub.history.length} days)` : ''}`);
    }
  }

  return result;
}

// ── Suggestions ───────────────────────────────────────────────────────────

function buildSuggestions(
  inboxStatuses: AgentMemoryStatus[],
  taskDisplay: TaskDisplay
): string[] {
  const suggestions: string[] = [];

  const needsConsolidation = inboxStatuses.filter((a) => a.inboxCount >= 3);
  for (const a of needsConsolidation) {
    suggestions.push(
      `${capitalize(a.agent)} has ${a.inboxCount} inbox items — consolidation ready`
    );
  }

  const hasInbox = inboxStatuses.filter((a) => a.inboxCount > 0 && a.inboxCount < 3);
  if (hasInbox.length > 0) {
    const names = hasInbox
      .map((a) => `${capitalize(a.agent)} (${a.inboxCount})`)
      .join(", ");
    suggestions.push(`Inbox items: ${names}`);
  }

  if (taskDisplay.openCount > 5) {
    suggestions.push(
      `${taskDisplay.openCount} open tasks — consider triaging or deferring some`
    );
  }

  return suggestions;
}

function capitalize(s: string): string {
  return s.charAt(0).toUpperCase() + s.slice(1);
}

// ── Main ──────────────────────────────────────────────────────────────────

function main() {
  const { date, time } = now();
  const hour = parseInt(time.slice(0, 2), 10);
  const greeting = getGreeting(hour);
  const inboxStatuses = scanInbox();
  const taskDisplay = loadTasks(date);
  const suggestions = buildSuggestions(inboxStatuses, taskDisplay);

  const lines: string[] = [];

  lines.push(greeting);
  lines.push("");

  lines.push("━━ Briefing ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
  lines.push("");

  if (taskDisplay.lines.length > 0) {
    lines.push("Tasks:");
    for (const line of taskDisplay.lines) {
      lines.push(`  ${line}`);
    }
    lines.push("");
    lines.push(
      `  Summary: ${taskDisplay.openCount} Open | ${taskDisplay.inProgressCount} In-Progress | ${taskDisplay.doneCount} Done`
    );
    lines.push("");
  } else {
    lines.push("Tasks: No open or in-progress tasks.");
    lines.push("");
  }

  if (suggestions.length > 0) {
    lines.push("Suggested:");
    for (const s of suggestions) {
      lines.push(`  > ${s}`);
    }
    lines.push("");
  }

  lines.push("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");

  process.stdout.write(lines.join("\n"));
}

try {
  main();
} catch (err) {
  process.stderr.write(
    `[morning] Error: ${err instanceof Error ? err.message : String(err)}\n`
  );
}

process.exit(0);

